import React, { useState, useEffect, useCallback } from 'react';
import { FaMapMarkerAlt, FaHistory, FaTimes } from 'react-icons/fa';

const AddressMemory = ({ 
  value, 
  onChange, 
  placeholder = "Enter address...",
  className = "",
  error = false,
  fieldType = "address" // address, city, state, zipCode, etc.
}) => {
  const [memorySuggestions, setMemorySuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [inputRef, setInputRef] = useState(null);

  // Address memory management
  const getAddressMemory = useCallback(() => {
    try {
      const stored = localStorage.getItem(`addressMemory_${fieldType}`);
      return stored ? JSON.parse(stored) : [];
    } catch (error) {
      console.error(`Error loading address memory for ${fieldType}:`, error);
      return [];
    }
  }, [fieldType]);

  const saveAddressToMemory = useCallback((address) => {
    if (!address || address.trim().length < 3) return;

    try {
      const memory = getAddressMemory();
      const newMemory = [
        { address: address.trim(), timestamp: Date.now() },
        ...memory.filter(item => item.address !== address.trim())
      ].slice(0, 10); // Keep only last 10 addresses

      localStorage.setItem(`addressMemory_${fieldType}`, JSON.stringify(newMemory));
      return newMemory;
    } catch (error) {
      console.error(`Error saving address to memory for ${fieldType}:`, error);
      return [];
    }
  }, [fieldType, getAddressMemory]);

  const getMemorySuggestions = useCallback((input) => {
    if (!input || input.length < 2) return [];

    const memory = getAddressMemory();
    return memory
      .filter(item => 
        item.address.toLowerCase().includes(input.toLowerCase())
      )
      .slice(0, 5); // Show max 5 memory suggestions
  }, [getAddressMemory]);

  const handleInputChange = useCallback((e) => {
    const inputValue = e.target.value;
    onChange(inputValue);

    // Get memory suggestions
    const suggestions = getMemorySuggestions(inputValue);
    setMemorySuggestions(suggestions);
    setShowSuggestions(suggestions.length > 0);
  }, [onChange, getMemorySuggestions]);

  const handleMemorySuggestionClick = useCallback((memorySuggestion) => {
    onChange(memorySuggestion.address);
    setShowSuggestions(false);
    setMemorySuggestions([]);
  }, [onChange]);

  const handleInputBlur = useCallback((e) => {
    const inputValue = e.target.value.trim();
    if (inputValue.length > 2) {
      saveAddressToMemory(inputValue);
    }

    // Delay hiding suggestions to allow clicking on them
    setTimeout(() => {
      setShowSuggestions(false);
    }, 200);
  }, [saveAddressToMemory]);

  const handleInputFocus = useCallback(() => {
    if (memorySuggestions.length > 0) {
      setShowSuggestions(true);
    }
  }, [memorySuggestions.length]);

  const clearMemory = useCallback(() => {
    try {
      localStorage.removeItem(`addressMemory_${fieldType}`);
      setMemorySuggestions([]);
      setShowSuggestions(false);
    } catch (error) {
      console.error(`Error clearing memory for ${fieldType}:`, error);
    }
  }, [fieldType]);

  return (
    <div className="relative">
      <div className="relative">
        <input
          ref={setInputRef}
          type="text"
          value={value}
          onChange={handleInputChange}
          onBlur={handleInputBlur}
          onFocus={handleInputFocus}
          className={`w-full pl-12 pr-10 py-3 border-2 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all duration-300 ${
            error ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-blue-500'
          } ${className}`}
          placeholder={placeholder}
          aria-invalid={error ? "true" : "false"}
          aria-describedby={error ? `${fieldType}-error` : undefined}
        />
        <FaMapMarkerAlt className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400 text-lg" />

        {/* Clear memory button */}
        {getAddressMemory().length > 0 && (
          <button
            type="button"
            onClick={clearMemory}
            className="absolute right-10 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-red-500 transition-colors"
            title="Clear address history"
          >
            <FaTimes className="h-4 w-4" />
          </button>
        )}
      </div>

      {/* Memory Suggestions */}
      {showSuggestions && memorySuggestions.length > 0 && (
        <div className="absolute top-full left-0 right-0 bg-white border border-gray-200 rounded-b-xl shadow-lg z-50 max-h-60 overflow-y-auto">
          <div className="px-4 py-2 bg-gray-50 border-b border-gray-200">
            <p className="text-xs font-semibold text-gray-600 uppercase tracking-wide flex items-center">
              <FaHistory className="mr-1" />
              Recent {fieldType} entries
            </p>
          </div>
          {memorySuggestions.map((memorySuggestion, index) => (
            <button
              key={`memory-${index}`}
              type="button"
              onClick={() => handleMemorySuggestionClick(memorySuggestion)}
              className="w-full px-4 py-3 text-left hover:bg-gray-50 border-b border-gray-100 last:border-b-0 transition-colors focus:outline-none focus:bg-gray-50"
            >
              <div className="flex items-start space-x-3">
                <FaMapMarkerAlt className="text-green-500 text-sm mt-1 flex-shrink-0" />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-gray-900 truncate">
                    {memorySuggestion.address}
                  </p>
                  <p className="text-xs text-gray-500">
                    Previously used
                  </p>
                </div>
              </div>
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

export default AddressMemory;

import React, { useState } from 'react';
import { 
  FaSearch, 
  FaFilter, 
  FaClock, 
  FaExclamationTriangle,
  FaCheckCircle,
  FaTimesCircle,
  FaEye,
  FaGavel,
  FaDollarSign,
  FaUser,
  FaHome,
  FaCalendar
} from 'react-icons/fa';

const AdminDisputesManagement = ({ disputes = [], loading = false, error = '', onResolveDispute, onRefresh }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [selectedDispute, setSelectedDispute] = useState(null);
  const [showResolutionModal, setShowResolutionModal] = useState(false);
  const [resolutionType, setResolutionType] = useState('');
  const [adminNotes, setAdminNotes] = useState('');
  const [actionLoading, setActionLoading] = useState(false);
  const [actionError, setActionError] = useState(null);

  // Enhanced mock disputes data with more details
  const enhancedDisputes = disputes.map(dispute => ({
    ...dispute,
    propertyTitle: dispute.propertyTitle || 'Luxury Villa in Lekki',
    buyerName: dispute.buyerName || 'John Doe',
    buyerEmail: dispute.buyerEmail || 'buyer@example.com',
    sellerName: dispute.sellerName || 'Jane Smith',
    sellerEmail: dispute.sellerEmail || 'seller@example.com',
    reason: dispute.reason || 'property_condition',
    description: dispute.description || 'Property condition does not match the description provided.',
    amount: dispute.amount || 5000000,
    createdAt: dispute.createdAt || new Date().toISOString(),
    evidence: dispute.evidence || [],
    priority: dispute.priority || 'high'
  }));

  const filteredDisputes = enhancedDisputes.filter(dispute => {
    const matchesSearch = 
      dispute.propertyTitle?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      dispute.buyerName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      dispute.sellerName?.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesFilter = filterStatus === 'all' || dispute.status === filterStatus;

    return matchesSearch && matchesFilter;
  });

  const getDisputeReasonLabel = (reason) => {
    const reasons = {
      'property_condition': 'Property Condition',
      'title_issues': 'Title Issues',
      'seller_non_compliance': 'Seller Non-Compliance',
      'buyer_non_compliance': 'Buyer Non-Compliance',
      'payment_issues': 'Payment Issues',
      'other': 'Other'
    };
    return reasons[reason] || reason;
  };

  const getDisputePriorityColor = (priority) => {
    const colors = {
      'high': 'bg-red-100 text-red-800 border-red-300',
      'medium': 'bg-yellow-100 text-yellow-800 border-yellow-300',
      'low': 'bg-blue-100 text-blue-800 border-blue-300'
    };
    return colors[priority] || colors.medium;
  };

  const handleResolve = (dispute) => {
    setSelectedDispute(dispute);
    setShowResolutionModal(true);
  };

  const handleConfirmResolution = async () => {
    if (!resolutionType || !adminNotes.trim()) {
      alert('Please select a resolution type and provide admin notes');
      return;
    }

    if (!onResolveDispute) {
      console.warn('onResolveDispute handler missing');
      return;
    }

    setActionLoading(true);
    setActionError(null);
    try {
      await onResolveDispute({
        disputeId: selectedDispute?.id,
        resolutionType,
        adminNotes
      });
      setShowResolutionModal(false);
      setResolutionType('');
      setAdminNotes('');
      setSelectedDispute(null);
    } catch (err) {
      setActionError(err.message || 'Failed to resolve dispute');
    } finally {
      setActionLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    const value = Number.isFinite(Number(amount)) ? Number(amount) : 0;
    const formatted = new Intl.NumberFormat('en-NG', {
      style: 'currency',
      currency: 'NGN',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(value);
    return formatted.replace(/\s/g, '\u00A0');
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-NG', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const getStatusBadge = (status) => {
    const config = {
      'pending': { icon: FaClock, color: 'bg-yellow-100 text-yellow-800', text: 'Pending' },
      'under_review': { icon: FaExclamationTriangle, color: 'bg-blue-100 text-blue-800', text: 'Under Review' },
      'resolved': { icon: FaCheckCircle, color: 'bg-green-100 text-green-800', text: 'Resolved' },
      'rejected': { icon: FaTimesCircle, color: 'bg-red-100 text-red-800', text: 'Rejected' }
    };

    const { icon: Icon, color, text } = config[status] || config.pending;

    return (
      <span className={`px-2 py-1 rounded-full text-xs font-medium flex items-center space-x-1 ${color}`}>
        <Icon className="h-3 w-3" />
        <span>{text}</span>
      </span>
    );
  };

  if (loading) {
    return <div className="h-64 flex items-center justify-center text-sm text-gray-500">Loading disputes...</div>;
  }
  if (error) {
    return <div className="h-64 flex items-center justify-center text-sm text-red-500">{error}</div>;
  }
  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Dispute Management</h2>
          <p className="text-gray-600 mt-1">Review and resolve transaction disputes</p>
        </div>
        <div className="flex items-center space-x-2">
          <div className="bg-yellow-50 px-4 py-2 rounded-lg border border-yellow-200">
            <span className="text-yellow-800 font-semibold">
              {filteredDisputes.filter(d => d.status === 'pending').length} Pending
            </span>
          </div>
          {onRefresh && (
            <button
              onClick={onRefresh}
              className="inline-flex items-center px-3 py-2 text-sm font-medium text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50"
            >
              Refresh
            </button>
          )}
        </div>
      </div>

      {/* Filters and Search */}
      <div className="bg-white rounded-lg shadow p-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="relative">
            <FaSearch className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              placeholder="Search by property, buyer, or seller..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
          <div className="relative">
            <FaFilter className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <select
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent appearance-none bg-white"
            >
              <option value="all">All Status</option>
              <option value="pending">Pending</option>
              <option value="under_review">Under Review</option>
              <option value="resolved">Resolved</option>
              <option value="rejected">Rejected</option>
            </select>
          </div>
        </div>
      </div>

      {/* Disputes List */}
      {filteredDisputes.length === 0 ? (
        <div className="bg-white rounded-lg shadow p-12 text-center">
          <FaExclamationTriangle className="text-4xl text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-gray-600 mb-2">No Disputes Found</h3>
          <p className="text-gray-500">No disputes match your search criteria.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filteredDisputes.map((dispute) => (
            <div key={dispute.id} className="bg-white rounded-lg shadow hover:shadow-md transition-shadow">
              <div className="p-6">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex-1">
                    <div className="flex items-center space-x-3 mb-2">
                      <span className={`px-3 py-1 rounded-full text-xs font-medium border ${getDisputePriorityColor(dispute.priority)}`}>
                        {dispute.priority.toUpperCase()} PRIORITY
                      </span>
                      {getStatusBadge(dispute.status)}
                    </div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-1">{dispute.propertyTitle}</h3>
                    <div className="flex items-center space-x-4 text-sm text-gray-600">
                      <span className="flex items-center">
                        <FaDollarSign className="mr-1" />
                        {formatCurrency(dispute.amount)}
                      </span>
                      <span className="flex items-center">
                        <FaCalendar className="mr-1" />
