                  setResolutionType('');
                  setAdminNotes('');
                  setSelectedDispute(null);
                }}
                className="px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
              >
                Cancel
              </button>
              <button
                onClick={handleConfirmResolution}
                disabled={actionLoading}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-60"
              >
                {actionLoading ? 'Processing...' : 'Confirm Resolution'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDisputesManagement;

import React, { useState, useEffect } from 'react';
import { FaBuilding, FaCheckCircle, FaTimesCircle, FaClock, FaEye, FaFileAlt } from 'react-icons/fa';
import toast from 'react-hot-toast';
import apiClient from '../services/apiClient';

const AdminMortgageBankVerification = () => {
  const [banks, setBanks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedBank, setSelectedBank] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [verificationNotes, setVerificationNotes] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');

  useEffect(() => {
    loadBanks();
  }, [filterStatus]);

  const loadBanks = async () => {
    try {
      setLoading(true);
      const url = filterStatus === 'all' ? '/admin/mortgage-banks' : `/admin/mortgage-banks?status=${filterStatus}`;
      const response = await apiClient.get(url);
      if (response.data?.success) {
        setBanks(response.data.data || []);
      }
    } catch (error) {
      console.error('Error loading banks:', error);
      toast.error('Failed to load mortgage banks');
    } finally {
      setLoading(false);
    }
  };

  const handleVerify = async (bankId, status) => {
    try {
      const response = await apiClient.put(`/admin/mortgage-banks/${bankId}/verify`, {
        verificationStatus: status,
        verificationNotes: verificationNotes
      });

      if (response.data?.success) {
        toast.success(`Bank ${status === 'approved' ? 'approved' : 'rejected'} successfully`);
        setShowModal(false);
        setSelectedBank(null);
        setVerificationNotes('');
        loadBanks();
      }
    } catch (error) {
      console.error('Error verifying bank:', error);
      toast.error(error.response?.data?.message || 'Failed to verify bank');
    }
  };

  const openModal = (bank) => {
    setSelectedBank(bank);
    setVerificationNotes(bank.verificationNotes || '');
    setShowModal(true);
  };

  const getStatusBadge = (status) => {
    const badges = {
      pending: 'bg-yellow-100 text-yellow-800',
      approved: 'bg-green-100 text-green-800',
      rejected: 'bg-red-100 text-red-800'
    };
    return badges[status] || 'bg-gray-100 text-gray-800';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
