    if (!trimmed) return null;

    const looksLikeJson = (
      (trimmed.startsWith('{') && trimmed.endsWith('}')) ||
      (trimmed.startsWith('[') && trimmed.endsWith(']'))
    );
    if (looksLikeJson) {
      try {
        const parsed = JSON.parse(trimmed);
        return normalizeImageValue(parsed);
      } catch (_) {
        // fall through to treat as plain string
      }
    }

    if (trimmed.includes(',')) {
      const parts = trimmed.split(',').map((p) => p.trim()).filter(Boolean);
      for (const part of parts) {
        const normalized = normalizeImageValue(part);
        if (normalized) return normalized;
      }
    }

    return trimmed;
  }

  if (Array.isArray(value)) {
    for (const entry of value) {
      const normalized = normalizeImageValue(entry);
      if (normalized) return normalized;
    }
    return null;
  }

  if (typeof value === 'object') {
    return (
      value.url ||
      value.secure_url ||
      value.secureUrl ||
      value.downloadUrl ||
      value.downloadURL ||
      value.imageUrl ||
      value.imageURL ||
      value.path ||
      value.src ||
      value.source ||
      value.uri ||
      normalizeImageValue(value.data)
    );
  }

  return null;
};

const collectPropertyImages = (property) => {
  if (!property) return [];

  const possibleSources = [
    property.images,
    property.media?.images,
    property.assets?.images,
    property.gallery,
    property.mediaItems,
    property.photos,
    property.files,
    property.attachments,
    property.details?.images,
    property.metadata?.images,
    property.uploads,
    property.image,
    property.primaryImage,
    property.mainImage,
    property.coverImage,
    property.featuredImage,
    property.thumbnail
  ];

  const urls = [];
  const pushUnique = (candidate) => {
    const normalized = normalizeImageValue(candidate);
    if (normalized && !urls.includes(normalized)) {
      urls.push(normalized);
    }
  };

  possibleSources.forEach((source) => {
    if (!source) return;

    if (Array.isArray(source)) {
      source.forEach(pushUnique);
    } else if (typeof source === 'object') {
      Object.values(source).forEach(pushUnique);
    } else {
      pushUnique(source);
    }
  });

  return urls;
};

const AdminPropertyDetailsModal = ({ property, isOpen, onClose, onApprove, onReject }) => {
  const [activeTab, setActiveTab] = useState('overview');
  const [rejectionReason, setRejectionReason] = useState('');
  const [adminNotes, setAdminNotes] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [showRejectionModal, setShowRejectionModal] = useState(false);
  const [selectedRejectionReason, setSelectedRejectionReason] = useState('');
  const [customRejectionReason, setCustomRejectionReason] = useState('');

  // Popular rejection reasons
  const popularRejectionReasons = [
    'Incomplete property information',
    'Poor quality photos',
    'Inaccurate pricing',
    'Missing required documents',
    'Property not available for sale/rent',
    'Duplicate listing',
    'Inappropriate content',
    'Location information incorrect',
    'Property description misleading',
    'Missing contact information'
  ];

  useEffect(() => {
    if (isOpen) {
      setActiveTab('overview');
      setRejectionReason('');
      setAdminNotes('');
      setError('');
      setShowRejectionModal(false);
      setSelectedRejectionReason('');
      setCustomRejectionReason('');
    }
  }, [isOpen, property]);

  const handleApprove = async () => {
    if (!property) return;
    
    setIsLoading(true);
    setError('');
    
    try {
      await onApprove(property.id, adminNotes);
      onClose();
    } catch (err) {
      setError('Failed to approve property. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleReject = () => {
    setShowRejectionModal(true);
  };

  const handleRejectSubmit = async () => {
    if (!property) return;
    
    const finalRejectionReason = selectedRejectionReason === 'other' 
      ? customRejectionReason.trim()
      : selectedRejectionReason;
    
    if (!finalRejectionReason) {
      setError('Please select a reason or provide a custom reason for rejection.');
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      await onReject(property.id, finalRejectionReason, adminNotes);
      setShowRejectionModal(false);
      onClose();
    } catch (err) {
      setError('Failed to reject property. Please try again.');
      console.error('Rejection error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleRejectCancel = () => {
    setShowRejectionModal(false);
    setSelectedRejectionReason('');
    setCustomRejectionReason('');
    setError('');
  };

  const formatPrice = (price) => {
    return new Intl.NumberFormat('en-NG', {
      style: 'currency',
      currency: 'NGN',
      minimumFractionDigits: 0
    }).format(price);
  };

  const getStatusBadge = (status) => {
    const statusConfig = {
      'active': { color: 'bg-green-100 text-green-800', label: 'Active' },
      'pending': { color: 'bg-yellow-100 text-yellow-800', label: 'Pending' },
      'inactive': { color: 'bg-gray-100 text-gray-800', label: 'Inactive' },
      'sold': { color: 'bg-blue-100 text-blue-800', label: 'Sold' },
      'rented': { color: 'bg-purple-100 text-purple-800', label: 'Rented' }
    };
    
    const config = statusConfig[status] || statusConfig['pending'];
    
    return (
      <span className={`px-2 py-1 text-xs font-medium rounded-full ${config.color}`}>
        {config.label}
      </span>
    );
  };

  const getApprovalStatusBadge = (status) => {
    const statusConfig = {
      'approved': { color: 'bg-green-100 text-green-800', label: 'Approved for Listing' },
      'pending': { color: 'bg-yellow-100 text-yellow-800', label: 'Pending Approval' },
      'rejected': { color: 'bg-red-100 text-red-800', label: 'Rejected' }
    };
    
    const config = statusConfig[status] || statusConfig['pending'];
    
    return (
      <span className={`px-2 py-1 text-xs font-medium rounded-full ${config.color}`}>
        {config.label}
      </span>
    );
  };

  const getVerificationStatusBadge = (status) => {
    const statusConfig = {
      'verified': { color: 'bg-green-100 text-green-800', label: '✓ Verified' },
      'unverified': { color: 'bg-gray-100 text-gray-800', label: 'Not Verified' }
    };
    
    const config = statusConfig[status] || statusConfig['unverified'];
    
    return (
      <span className={`px-2 py-1 text-xs font-medium rounded-full ${config.color}`}>
        {config.label}
      </span>
    );
  };

  const propertyImages = useMemo(() => collectPropertyImages(property), [property]);

  if (!isOpen || !property) return null;

  const tabs = [
    { id: 'overview', label: 'Overview', icon: FaEye },
    { id: 'images', label: 'Images', icon: FaImage },
    { id: 'videos', label: 'Videos', icon: FaVideo },
    { id: 'documents', label: 'Documents', icon: FaFileAlt },
    { id: 'location', label: 'Location', icon: FaMapMarkerAlt }
  ];

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-2 sm:p-4 z-50">
      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
      <div className="bg-white rounded-lg max-w-6xl w-full max-h-[90vh] flex flex-col overflow-hidden shadow-xl">
        {/* Header */}
        <div className="flex flex-col gap-4 md:flex-row md:justify-between md:items-center p-4 sm:p-6 border-b">
          <div className="min-w-0">
            <h2 className="text-xl sm:text-2xl font-bold text-gray-900 break-words">{property.title}</h2>
            <div className="flex flex-wrap items-center gap-2 sm:gap-4 mt-3 text-sm">
              {getStatusBadge(property.status)}
              {getApprovalStatusBadge(property.approvalStatus || property.verificationStatus)}
              {(property.isVerified || property.approvalStatus === 'approved') && getVerificationStatusBadge('verified')}
              <span className="text-lg sm:text-2xl font-bold text-blue-600 whitespace-nowrap">{formatPrice(property.price)}</span>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="self-start md:self-auto text-gray-400 hover:text-gray-600 transition-colors"
            aria-label="Close property details"
          >
            <FaTimes className="w-6 h-6" />
          </button>
        </div>

        {/* Tabs */}
        <div className="border-b">
          <nav className="flex overflow-x-auto no-scrollbar px-4 sm:px-6" aria-label="Property detail sections">
            <div className="flex min-w-max space-x-6 sm:space-x-8">
              {tabs.map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
