                {/* Map placeholder */}
                <div className="h-64 bg-gray-200 rounded-lg flex items-center justify-center">
                  <div className="text-center text-gray-500">
                    <FaMapMarkerAlt className="w-8 h-8 mx-auto mb-2" />
