import React, { useState, useRef } from 'react';
import { FaUser, FaCamera, FaTimes, FaCheck } from 'react-icons/fa';
import storageService from '../services/storageService';
import { useAuth } from '../contexts/AuthContext';
import toast from 'react-hot-toast';

const AvatarUpload = ({ 
  currentAvatar, 
  onAvatarChange, 
  size = 'large', 
  disabled = false,
  showEditButton = true 
}) => {
  const [uploading, setUploading] = useState(false);
  const [preview, setPreview] = useState(null);
  const fileInputRef = useRef(null);
  const { user } = useAuth();

  const sizeClasses = {
    small: 'w-16 h-16',
    medium: 'w-24 h-24',
    large: 'w-32 h-32',
    xlarge: 'w-40 h-40'
  };

  const iconSizes = {
    small: 'text-lg',
    medium: 'text-2xl',
    large: 'text-3xl',
    xlarge: 'text-4xl'
  };

  const handleFileSelect = async (file) => {
    if (uploading || disabled) return;

    // Validate file
    const validation = storageService.validateFile(
      file, 
      ['image/jpeg', 'image/png', 'image/webp'], 
      5 * 1024 * 1024 // 5MB
    );

    if (!validation.valid) {
      validation.errors.forEach(error => {
        toast.error(error);
      });
      return;
    }

    // Create preview
    const reader = new FileReader();
    reader.onload = (e) => {
      setPreview(e.target.result);
    };
    reader.readAsDataURL(file);

    setUploading(true);

    try {
      // Use user ID if available, otherwise use a default ID
      const userId = user?.uid || 'default-user';
      const uploadResult = await storageService.uploadUserAvatar(file, userId);

      if (uploadResult.success) {
        onAvatarChange && onAvatarChange(uploadResult);
        toast.success('Avatar updated successfully!');
      } else {
        throw new Error(uploadResult.error || 'Upload failed');
      }
    } catch (error) {
      console.error('Avatar upload error:', error);

      // If upload fails, persist the preview locally so the user still sees the image
      if (preview) {
        try {
          const fallbackUserId = user?.id || user?.uid || 'default-user';
          const avatarInfo = {
            userId: fallbackUserId,
            avatarUrl: preview,
            uploadDate: new Date().toISOString(),
            fileName: file.name,
            isLocalFallback: true
          };
          localStorage.setItem(`user_avatar_${fallbackUserId}`, JSON.stringify(avatarInfo));

          // Notify parent with a local fallback result (keeps UI consistent)
          onAvatarChange && onAvatarChange({ success: true, url: preview, path: `local/${fallbackUserId}`, name: file.name, size: file.size, type: file.type, isFallback: true });
          toast.success('Using local preview until upload succeeds');
        } catch (e) {
          console.error('Failed to persist local avatar fallback:', e);
          toast.error('Failed to upload avatar');
          setPreview(null);
        }
      } else {
        toast.error('Failed to upload avatar');
        setPreview(null);
      }
    } finally {
      setUploading(false);
    }
  };

  const handleFileInputChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      handleFileSelect(file);
    }
    // Reset input value
    e.target.value = '';
  };

  const handleRemoveAvatar = async () => {
    if (uploading || disabled) return;

    try {
      // If there's a current avatar, delete it from storage
      if (currentAvatar && currentAvatar.path) {
        await storageService.deleteFile(currentAvatar.path);
      }

      onAvatarChange && onAvatarChange(null);
      setPreview(null);
      toast.success('Avatar removed successfully');
    } catch (error) {
      console.error('Error removing avatar:', error);
      toast.error('Failed to remove avatar');
    }
  };

  const openFileDialog = () => {
    if (!disabled && !uploading) {
      fileInputRef.current?.click();
    }
  };

  const displayAvatar = preview || currentAvatar?.url;

  return (
    <div className="avatar-upload">
      <div className="relative inline-block">
        {/* Avatar Display */}
        <div className={`
          ${sizeClasses[size]} rounded-full overflow-hidden border-4 border-white shadow-lg
          ${disabled ? 'opacity-50' : ''}
        `}>
          {displayAvatar ? (
            <img
              src={displayAvatar}
              alt="User avatar"
              className="w-full h-full object-cover"
            />
          ) : (
            <div className="w-full h-full bg-gray-200 flex items-center justify-center">
              <FaUser className={`${iconSizes[size]} text-gray-400`} />
            </div>
          )}
        </div>

        {/* Upload Overlay */}
        {!disabled && showEditButton && (
          <div className="absolute inset-0 rounded-full bg-black bg-opacity-0 hover:bg-opacity-30 transition-all duration-200 flex items-center justify-center group">
            <button
              onClick={openFileDialog}
              disabled={uploading}
              className="opacity-0 group-hover:opacity-100 transition-opacity duration-200 p-2 bg-white bg-opacity-90 rounded-full hover:bg-opacity-100"
            >
              {uploading ? (
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-gray-700"></div>
              ) : (
                <FaCamera className="text-gray-700 text-sm" />
              )}
            </button>
          </div>
        )}

        {/* Remove Button */}
        {!disabled && displayAvatar && (
          <button
            onClick={handleRemoveAvatar}
            disabled={uploading}
            className="absolute -top-2 -right-2 p-1 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors"
          >
            <FaTimes className="text-xs" />
          </button>
        )}

        {/* Upload Status */}
        {uploading && (
          <div className="absolute inset-0 rounded-full bg-black bg-opacity-50 flex items-center justify-center">
            <div className="text-white text-center">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-white mx-auto mb-2"></div>
              <p className="text-xs">Uploading...</p>
            </div>
          </div>
        )}
      </div>

      {/* Hidden File Input */}
      <input
        ref={fileInputRef}
        type="file"
        accept="image/jpeg,image/png,image/webp"
        onChange={handleFileInputChange}
        className="hidden"
        disabled={disabled || uploading}
      />

      {/* Upload Instructions */}
      {!disabled && (
        <div className="mt-3 text-center">
          <p className="text-xs text-gray-500">
            Click to upload new avatar
          </p>
          <p className="text-xs text-gray-400">
            JPG, PNG, WEBP up to 5MB
          </p>
        </div>
      )}
    </div>
  );
};

export default AvatarUpload;

import React, { useEffect, useMemo, useState } from 'react';
import Modal from './Modal';
import { useAuth } from '../contexts/AuthContext-new';
import toast from 'react-hot-toast';
import { getApiUrl } from '../utils/apiConfig';

const defaultPreferences = {
  propertyTypes: [],
  budgetRange: '',
  locations: [],
  investmentInterest: false,
  notifications: true
};

const BecomeBuyerModal = ({
  isOpen,
  onClose,
  mode = 'create',
  initialPreferences = {},
  buyerSince
}) => {
  const { addRole, currentUser, accessToken, setUserLocally, refreshCurrentUser } = useAuth();
  const [loading, setLoading] = useState(false);
  const [preferences, setPreferences] = useState({ ...defaultPreferences, ...initialPreferences });
  const [errors, setErrors] = useState({});

  useEffect(() => {
    if (isOpen) {
      setPreferences({ ...defaultPreferences, ...initialPreferences });
      setErrors({});
    }
  }, [isOpen, initialPreferences]);

  const isBuyer = useMemo(
    () => Array.isArray(currentUser?.roles) && currentUser.roles.includes('buyer'),
    [currentUser?.roles]
  );
  const isEditing = mode === 'edit' || isBuyer;

  const propertyTypes = [
    'Apartment', 'House', 'Land', 'Commercial', 'Office Space', 'Shortlet'
  ];

  const budgetRanges = [
    'Under 5M', '5M - 10M', '10M - 20M', '20M - 50M', '50M - 100M', 'Over 100M'
  ];

  const locations = [
    'Lagos', 'Abuja', 'Port Harcourt', 'Kano', 'Ibadan', 'Enugu'
  ];

  const validatePreferences = () => {
    const nextErrors = {};
    if (!preferences.propertyTypes.length) {
      nextErrors.propertyTypes = 'Select at least one property type';
    }
    if (!preferences.locations.length) {
      nextErrors.locations = 'Choose at least one preferred location';
    }
    setErrors(nextErrors);
    return Object.keys(nextErrors).length === 0;
  };

  const handlePropertyTypeChange = (type) => {
    setPreferences(prev => ({
      ...prev,
      propertyTypes: prev.propertyTypes.includes(type)
        ? prev.propertyTypes.filter(t => t !== type)
        : [...prev.propertyTypes, type]
    }));
  };

  const handleLocationChange = (location) => {
    setPreferences(prev => ({
      ...prev,
      locations: prev.locations.includes(location)
        ? prev.locations.filter(l => l !== location)
        : [...prev.locations, location]
    }));
  };

  const buildAuthHeaders = () => {
    const headers = { 'Content-Type': 'application/json' };
    if (accessToken) {
      headers.Authorization = `Bearer ${accessToken}`;
    } else if (currentUser?.email) {
      headers['X-Mock-User-Email'] = currentUser.email;
    }
    return headers;
  };

  const submit = async (e) => {
    e.preventDefault();
    if (!validatePreferences()) return;
    setLoading(true);

    try {
      // Ensure buyer role is present even if backend request fails
      try {
        await addRole('buyer', false);
      } catch (roleErr) {
        console.warn('Failed to ensure buyer role before onboarding', roleErr);
      }

      const endpoint = isBuyer ? '/buyer/preferences' : '/buyer/profile';
      const method = isBuyer ? 'PUT' : 'POST';
      const payload = isBuyer
        ? { preferences }
        : {
            userId: currentUser.id,
            preferences,
            buyerSince: buyerSince || new Date().toISOString(),
            source: 'profile_settings_modal'
          };

      const response = await fetch(getApiUrl(endpoint), {
        method,
        headers: buildAuthHeaders(),
        body: JSON.stringify(payload)
      });

      const allowFallback = response && response.status === 404;
      const json = await response.json().catch(() => ({}));
      if ((!response || !response.ok) && !allowFallback) {
        throw new Error(json.message || 'Failed to save buyer profile');
      }

      let synced = false;
      // Use backend response data if available, otherwise construct fallback
      const responseData = json?.data || {};
      const updatedUser = responseData.id ? responseData : null;

      if (setUserLocally) {
        if (updatedUser) {
          setUserLocally(updatedUser);
          synced = true;
        } else {
          const normalizedRoles = Array.from(new Set([
            ...(currentUser?.roles || []),
            'user',
            'buyer'
          ]));

          const updatedBuyerData = {
            ...(currentUser?.buyerData || {}),
            preferences,
            buyerSince: buyerSince || currentUser?.buyerData?.buyerSince || new Date().toISOString(),
            source: currentUser?.buyerData?.source || 'profile_settings_modal',
            updatedAt: new Date().toISOString()
          };

          setUserLocally({
            ...currentUser,
            roles: normalizedRoles,
            activeRole: 'buyer',
            buyerData: updatedBuyerData
          });
          synced = true;
        }
      }

      if (!synced && refreshCurrentUser) {
        try {
          await refreshCurrentUser();
          synced = true;
        } catch (syncErr) {
          console.warn('Unable to refresh user after buyer onboarding', syncErr);
        }
      }

      const summary = `${preferences.propertyTypes.length} type(s), ${preferences.locations.length} location(s)`;
      toast.success(
        isBuyer
          ? `Buyer preferences updated (${summary})`
          : `Welcome aboard! Buyer profile created (${summary})`
      );

      if (onClose) onClose();
    } catch (err) {
      console.error('BecomeBuyer submit error', err);
      toast.error(err.message || 'Failed to become buyer');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={isBuyer ? 'Update buyer preferences' : 'Become a Buyer'}
    >
      <form onSubmit={submit} className="space-y-6">
        {isBuyer ? (
          <div className="text-sm text-gray-600">
            <p>Fine-tune your preferences to improve recommendations and alerts.</p>
          </div>
        ) : (
          <div className="text-sm text-gray-600">
            <p>As a buyer, you'll be able to:</p>
            <ul className="mt-2 list-disc list-inside space-y-1">
              <li>Save properties to your wishlist</li>
              <li>Make property inquiries</li>
              <li>Track your favorite listings</li>
              <li>Get personalized recommendations</li>
              <li>Participate in property investments</li>
            </ul>
          </div>
        )}

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            What types of properties are you interested in?
          </label>
          <div className="grid grid-cols-2 gap-2">
            {propertyTypes.map(type => (
              <label key={type} className="flex items-center">
                <input
                  type="checkbox"
                  checked={preferences.propertyTypes.includes(type)}
                  onChange={() => handlePropertyTypeChange(type)}
                  className="mr-2"
                />
                <span className="text-sm">{type}</span>
              </label>
            ))}
          </div>
          {errors.propertyTypes && (
            <p className="text-xs text-red-500 mt-1">{errors.propertyTypes}</p>
          )}
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            What's your budget range?
          </label>
          <select
            value={preferences.budgetRange}
            onChange={(e) => setPreferences(prev => ({ ...prev, budgetRange: e.target.value }))}
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500"
          >
            <option value="">Select budget range</option>
            {budgetRanges.map(range => (
              <option key={range} value={range}>{range}</option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Preferred locations
          </label>
          <div className="grid grid-cols-2 gap-2">
            {locations.map(location => (
              <label key={location} className="flex items-center">
                <input
                  type="checkbox"
                  checked={preferences.locations.includes(location)}
                  onChange={() => handleLocationChange(location)}
                  className="mr-2"
                />
                <span className="text-sm">{location}</span>
              </label>
            ))}
          </div>
          {errors.locations && (
            <p className="text-xs text-red-500 mt-1">{errors.locations}</p>
          )}
        </div>

        <div>
          <label className="flex items-center gap-2">
            <input
              type="checkbox"
              checked={preferences.investmentInterest}
              onChange={(e) => setPreferences(prev => ({ ...prev, investmentInterest: e.target.checked }))}
              className="mr-2"
            />
            <span className="text-sm">Interested in property investment opportunities</span>
          </label>
        </div>

        <div>
          <label className="flex items-center gap-2">
            <input
              type="checkbox"
              checked={preferences.notifications}
              onChange={(e) => setPreferences(prev => ({ ...prev, notifications: e.target.checked }))}
              className="mr-2"
            />
            <span className="text-sm">Send me notifications about matching properties</span>
          </label>
        </div>

        <div className="flex gap-2 pt-4">
          <button
            type="submit"
            disabled={loading}
            className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-medium py-2 px-4 rounded-md disabled:opacity-50"
          >
            {loading ? 'Processing...' : isBuyer ? 'Save preferences' : 'Become a Buyer'}
          </button>
          <button
            type="button"
            onClick={onClose}
            className="flex-1 bg-gray-200 hover:bg-gray-300 text-gray-800 font-medium py-2 px-4 rounded-md"
          >
            Cancel
          </button>
        </div>
      </form>
    </Modal>
  );
};

export default BecomeBuyerModal;

import React, { useState, useCallback } from 'react';
import { FaUpload, FaTimes, FaEye, FaPlay, FaFile, FaCheck, FaExclamationTriangle } from 'react-icons/fa';
import storageService from '../services/storageService';
import { useAuth } from '../contexts/AuthContext';
import toast from 'react-hot-toast';

const EnhancedFileUpload = ({ 
  propertyId, 
  onFilesChange, 
  initialFiles = [], 
  maxFiles = 10,
  maxSize = 10 * 1024 * 1024, // 10MB default
  allowedTypes = [],
  type = 'image', // 'image', 'video', 'document'
  disabled = false,
  className = ''
}) => {
  const [files, setFiles] = useState(initialFiles);
  const [uploadingFiles, setUploadingFiles] = useState(new Map());
  const [dragActive, setDragActive] = useState(false);
  const [previewIndex, setPreviewIndex] = useState(null);
  const { user } = useAuth();

  const getTypeConfig = () => {
    const configs = {
      image: {
        icon: FaUpload,
        accept: 'image/jpeg,image/png,image/webp,image/gif',
        allowedTypes: ['image/jpeg', 'image/png', 'image/webp', 'image/gif'],
        maxSize: 10 * 1024 * 1024, // 10MB
        placeholder: 'Click to upload or drag and drop images',
        subtext: 'PNG, JPG, WEBP, GIF up to 10MB each'
      },
      video: {
        icon: FaPlay,
        accept: 'video/mp4,video/webm,video/ogg,video/quicktime',
        allowedTypes: ['video/mp4', 'video/webm', 'video/ogg', 'video/quicktime'],
        maxSize: 100 * 1024 * 1024, // 100MB
        placeholder: 'Click to upload or drag and drop videos',
        subtext: 'MP4, WEBM, OGG, MOV up to 100MB each'
      },
      document: {
        icon: FaFile,
        accept: '.pdf,.doc,.docx,.txt,.rtf,.odt',
        allowedTypes: ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'text/plain', 'application/rtf', 'application/vnd.oasis.opendocument.text'],
        maxSize: 25 * 1024 * 1024, // 25MB
        placeholder: 'Click to upload or drag and drop documents',
        subtext: 'PDF, DOC, DOCX, TXT, RTF up to 25MB each'
      }
    };
    return configs[type] || configs.image;
  };

  const config = getTypeConfig();
  const finalAllowedTypes = allowedTypes.length > 0 ? allowedTypes : config.allowedTypes;
  const finalMaxSize = maxSize || config.maxSize;

  const handleUpload = useCallback(async (fileList) => {
    if (!user || disabled) return;

    const fileArray = Array.from(fileList);

    // Check if adding these files would exceed maxFiles limit
    if (files.length + fileArray.length > maxFiles) {
      toast.error(`Maximum ${maxFiles} ${type}s allowed`);
      return;
    }

    // Validate files
    const validFiles = [];
    const invalidFiles = [];

    fileArray.forEach(file => {
      const validation = storageService.validateFile(file, finalAllowedTypes, finalMaxSize);

      if (validation.valid) {
        validFiles.push(file);
      } else {
        invalidFiles.push({ file, errors: validation.errors });
      }
    });

    // Show validation errors
    if (invalidFiles.length > 0) {
      invalidFiles.forEach(({ file, errors }) => {
        errors.forEach(error => {
          toast.error(`${file.name}: ${error}`);
        });
      });
    }

    if (validFiles.length === 0) return;

    // Upload files with progress tracking
    for (const file of validFiles) {
      const fileId = `${Date.now()}_${Math.random()}`;

      // Add to uploading state
      setUploadingFiles(prev => new Map(prev).set(fileId, {
        file,
        progress: 0,
        status: 'uploading'
      }));

      try {
        const uploadResult = await uploadFileWithProgress(file, propertyId || 'temp', user.uid, fileId);

        if (uploadResult.success) {
          const newFile = {
            id: Date.now() + Math.random(),
            url: uploadResult.url,
            name: uploadResult.name,
            size: uploadResult.size,
            path: uploadResult.path,
            type: uploadResult.type,
            // Treat Firebase uploads as "uploaded" and local fallbacks as non-uploaded
            isUploaded: !uploadResult.isLocal
          };

          setFiles(prev => [...prev, newFile]);
          onFilesChange && onFilesChange([...files, newFile]);

          // Update progress to complete
          setUploadingFiles(prev => {
            const newMap = new Map(prev);
            newMap.set(fileId, { ...newMap.get(fileId), progress: 100, status: 'completed' });
            return newMap;
          });

          // Remove from uploading state after a delay
          setTimeout(() => {
            setUploadingFiles(prev => {
              const newMap = new Map(prev);
              newMap.delete(fileId);
              return newMap;
            });
          }, 2000);

          toast.success(`${file.name} uploaded successfully!`);
        } else {
          throw new Error(uploadResult.error || 'Upload failed');
        }
      } catch (error) {
        console.error('File upload error:', error);

        // Update progress to error
        setUploadingFiles(prev => {
          const newMap = new Map(prev);
          newMap.set(fileId, { ...newMap.get(fileId), status: 'error' });
          return newMap;
        });

        toast.error(`Failed to upload ${file.name}`);

        // Remove from uploading state after a delay
        setTimeout(() => {
          setUploadingFiles(prev => {
            const newMap = new Map(prev);
            newMap.delete(fileId);
            return newMap;
          });
        }, 3000);
      }
    }
  }, [user, disabled, files, maxFiles, type, finalAllowedTypes, finalMaxSize, propertyId, onFilesChange]);

  const uploadFileWithProgress = async (file, propertyId, userId, fileId) => {
    try {
      // Use storageService to upload the file
      const result = await storageService.uploadFile(file, userId);

      if (result.success) {
        // Simulate progress updates for UX
        setUploadingFiles(prev => {
          const newMap = new Map(prev);
          newMap.set(fileId, { ...newMap.get(fileId), progress: 100 });
          return newMap;
        });

        return {
          success: true,
          url: result.url || result.path,
          path: result.path,
          name: file.name,
          size: file.size,
          type: file.type,
          isLocal: false
        };
      } else {
        // Fallback: Store file in localStorage as base64 for persistence
        try {
          const reader = new FileReader();
          reader.onload = (e) => {
            const base64Data = e.target.result;
            const storageKey = `file_${fileId}`;
            localStorage.setItem(storageKey, JSON.stringify({
              name: file.name,
              size: file.size,
              type: file.type,
              data: base64Data
            }));
          };
          reader.readAsDataURL(file);

          // Return data URL immediately for display
          const dataUrl = await new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = (e) => resolve(e.target.result);
            reader.readAsDataURL(file);
          });

          console.warn(`Storing ${type} in localStorage for:`, file.name);

          return {
            success: true,
            url: dataUrl,
            path: `local-storage/${fileId}`,
            name: file.name,
            size: file.size,
            type: file.type,
            isLocal: true
          };
        } catch (storageError) {
          console.error('Failed to store in localStorage, using blob URL:', storageError);
          // Final fallback to blob URL
          const localUrl = URL.createObjectURL(file);
          return {
            success: true,
            url: localUrl,
            path: `local-files/${fileId}`,
            name: file.name,
            size: file.size,
            type: file.type,
            isLocal: true
          };
        }
      }
    } catch (error) {
      console.error('Error uploading file:', error);

      // Fallback: Store in localStorage as base64
      if (type === 'image' || type === 'document' || type === 'video') {
        try {
          const dataUrl = await new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = (e) => resolve(e.target.result);
            reader.readAsDataURL(file);
          });

          const storageKey = `file_${fileId}`;
          localStorage.setItem(storageKey, JSON.stringify({
            name: file.name,
            size: file.size,
            type: file.type,
            data: dataUrl
          }));

          console.warn(`Storing ${type} in localStorage for:`, file.name);

          return {
            success: true,
            url: dataUrl,
            path: `local-storage/${fileId}`,
            name: file.name,
            size: file.size,
            type: file.type,
            isLocal: true
          };
        } catch (storageError) {
          console.error('Failed to store in localStorage:', storageError);
          // Final fallback to blob URL
          const localUrl = URL.createObjectURL(file);
          return {
            success: true,
            url: localUrl,
            path: `local-files/${fileId}`,
            name: file.name,
            size: file.size,
            type: file.type,
            isLocal: true
          };
        }
      }

      return {
        success: false,
        error: error.message
      };
    }
  };

  const handleRemoveFile = async (index) => {
    if (disabled) return;

    const fileToRemove = files[index];

    // If it's an uploaded file, delete from storage
    if (fileToRemove.isUploaded && fileToRemove.path) {
      try {
        await storageService.deleteFile(fileToRemove.path);
      } catch (error) {
        console.error('Error deleting file from storage:', error);
        // Continue with removal from UI even if storage deletion fails
      }
    }

    const updatedFiles = files.filter((_, i) => i !== index);
    setFiles(updatedFiles);
    onFilesChange && onFilesChange(updatedFiles);
    toast.success('File removed successfully');
  };

  const handleFileSelect = (e) => {
    const fileList = e.target.files;
    if (fileList.length > 0) {
      handleUpload(fileList);
    }
    // Reset input value
    e.target.value = '';
  };

  const handleDragOver = (e) => {
    e.preventDefault();
    setDragActive(true);
  };

  const handleDragLeave = (e) => {
    e.preventDefault();
    setDragActive(false);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setDragActive(false);
    const fileList = e.dataTransfer.files;
    if (fileList.length > 0) {
      handleUpload(fileList);
    }
  };

  const renderPreview = (file, index) => {
    if (type === 'image') {
      return (
        <div className="aspect-square bg-gray-100 rounded-lg overflow-hidden">
          <img
            src={file.url}
            alt={`${type} ${index + 1}`}
            className="w-full h-full object-cover"
          />
        </div>
      );
    } else if (type === 'video') {
      return (
        <div className="aspect-video bg-gray-100 rounded-lg overflow-hidden relative">
          <video
            src={file.url}
            className="w-full h-full object-cover"
            controls={false}
          />
          <div className="absolute inset-0 flex items-center justify-center bg-black bg-opacity-30">
            <FaPlay className="text-white text-2xl" />
          </div>
        </div>
      );
    } else {
      return (
        <div className="aspect-square bg-gray-100 rounded-lg overflow-hidden flex items-center justify-center">
          <FaFile className="text-gray-400 text-3xl" />
        </div>
      );
    }
  };

  const renderUploadingFiles = () => {
    const uploadingArray = Array.from(uploadingFiles.values());
    if (uploadingArray.length === 0) return null;

    return (
      <div className="mt-4">
        <h4 className="text-sm font-medium text-gray-700 mb-3">
          Uploading ({uploadingArray.length})
        </h4>
        <div className="space-y-3">
          {uploadingArray.map((uploadingFile, index) => (
            <div key={`uploading_${index}`} className="flex items-center space-x-3 p-3 bg-gray-50 rounded-lg">
              <div className="flex-shrink-0">
                {uploadingFile.status === 'completed' ? (
                  <FaCheck className="text-green-500" />
                ) : uploadingFile.status === 'error' ? (
                  <FaExclamationTriangle className="text-red-500" />
                ) : (
                  <config.icon className="text-blue-500" />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-gray-900 truncate">
                  {uploadingFile.file.name}
                </p>
                <div className="w-full bg-gray-200 rounded-full h-2 mt-1">
                  <div 
                    className={`h-2 rounded-full transition-all duration-300 ${
                      uploadingFile.status === 'completed' ? 'bg-green-500' :
                      uploadingFile.status === 'error' ? 'bg-red-500' : 'bg-blue-500'
                    }`}
                    style={{ width: `${uploadingFile.progress}%` }}
                  />
                </div>
                <p className="text-xs text-gray-500 mt-1">
                  {uploadingFile.status === 'completed' ? 'Upload complete' :
                   uploadingFile.status === 'error' ? 'Upload failed' :
                   `${Math.round(uploadingFile.progress)}% uploaded`}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderPreviewModal = () => {
    if (previewIndex === null) return null;

    const file = files[previewIndex];
    if (!file) return null;

    return (
      <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 p-4">
        <div className="relative max-w-4xl max-h-full">
          <button
            onClick={() => setPreviewIndex(null)}
            className="absolute top-4 right-4 p-2 bg-white bg-opacity-90 rounded-full hover:bg-opacity-100 transition-all z-10"
          >
            <FaTimes className="text-gray-700" />
          </button>

          {type === 'image' ? (
            <img
              src={file.url}
              alt={`${type} ${previewIndex + 1}`}
              className="max-w-full max-h-full object-contain rounded-lg"
            />
          ) : type === 'video' ? (
            <video
              src={file.url}
              controls
              className="max-w-full max-h-full rounded-lg"
            />
          ) : (
            <div className="bg-white rounded-lg p-8 max-w-md">
              <FaFile className="text-gray-400 text-6xl mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 text-center">{file.name}</h3>
              <p className="text-sm text-gray-500 text-center mt-2">
                {storageService.formatFileSize(file.size)}
              </p>
              <a
                href={file.url}
                target="_blank"
                rel="noopener noreferrer"
                className="block mt-4 text-center text-blue-600 hover:text-blue-800"
              >
                Download File
              </a>
            </div>
          )}

          <div className="absolute bottom-4 left-4 right-4 bg-black bg-opacity-50 text-white p-3 rounded-lg">
            <p className="text-sm">
              {file.name} ({storageService.formatFileSize(file.size)})
            </p>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className={`enhanced-file-upload ${className}`}>
      {/* Upload Area */}
      <div
        className={`
          border-2 border-dashed rounded-lg p-6 text-center transition-all duration-200
          ${disabled ? 'border-gray-200 bg-gray-50 cursor-not-allowed' : 
            dragActive ? 'border-brand-blue bg-blue-50' : 'border-gray-300 hover:border-brand-blue cursor-pointer'}
        `}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onClick={() => !disabled && document.getElementById(`${type}-upload`).click()}
      >
        <input
          id={`${type}-upload`}
          type="file"
          multiple
          accept={config.accept}
          onChange={handleFileSelect}
          className="hidden"
          disabled={disabled}
        />

        <div className="space-y-2">
          <config.icon className={`mx-auto text-3xl ${disabled ? 'text-gray-300' : 'text-gray-400'}`} />

          <div className="space-y-1">
            <p className="text-sm font-medium text-gray-700">
              {disabled ? `${type} upload disabled` : config.placeholder}
            </p>
            <p className="text-xs text-gray-500">
              {config.subtext}
            </p>
            <p className="text-xs text-gray-500">
              {files.length}/{maxFiles} {type}s uploaded
            </p>
          </div>
        </div>
      </div>

      {/* Uploading Files */}
      {renderUploadingFiles()}

      {/* Files Grid */}
      {files.length > 0 && (
        <div className="mt-6">
          <h4 className="text-sm font-medium text-gray-700 mb-3">
            {type.charAt(0).toUpperCase() + type.slice(1)}s ({files.length})
          </h4>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
            {files.map((file, index) => (
              <div key={file.id || index} className="relative group">
                {renderPreview(file, index)}

                {/* Local/Temporary Badge */}
                {file.isLocal && !file.url?.startsWith('http') && (
                  <div className="absolute top-1 right-1 bg-yellow-500 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1">
                    <FaExclamationTriangle className="text-xs" />
                    Temporary
                  </div>
                )}

                {/* Overlay */}
                <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-30 transition-all duration-200 rounded-lg flex items-center justify-center">
                  <div className="opacity-0 group-hover:opacity-100 transition-opacity duration-200 flex space-x-2">
                    <button
                      onClick={() => setPreviewIndex(index)}
                      className="p-2 bg-white bg-opacity-90 rounded-full hover:bg-opacity-100 transition-all"
                      title="Preview"
                    >
                      <FaEye className="text-gray-700 text-sm" />
                    </button>

                    {!disabled && (
                      <button
                        onClick={() => handleRemoveFile(index)}
                        className="p-2 bg-red-500 bg-opacity-90 rounded-full hover:bg-opacity-100 transition-all"
                        title="Remove"
                      >
                        <FaTimes className="text-white text-sm" />
                      </button>
                    )}
                  </div>
                </div>

                {/* File Info */}
                <div className="mt-1">
                  <p className="text-xs text-gray-500 truncate">
                    {file.name}
                  </p>
                  <p className="text-xs text-gray-400">
                    {storageService.formatFileSize(file.size)}
                  </p>
                </div>
              </div>
            ))}
          </div>

          {/* Warning for temporary files */}
          {files.some(f => f.isLocal && !f.url?.startsWith('http')) && (
            <div className="mt-4 p-3 bg-yellow-50 border border-yellow-200 rounded-lg flex gap-2">
              <FaExclamationTriangle className="text-yellow-600 flex-shrink-0 mt-0.5" />
              <p className="text-xs text-yellow-800">
                Some images are temporarily stored locally and may not persist after page reload. Make sure to have a stable connection to allow automatic upload to complete.
              </p>
            </div>
          )}
        </div>
      )}

      {/* Preview Modal */}
      {renderPreviewModal()}
    </div>
  );
};

export default EnhancedFileUpload;

import React, { useState, useEffect } from 'react';
import { useEscrow } from '../contexts/EscrowContext';
import { 
  FaBell, 
  FaTimes, 
  FaCheck, 
  FaExclamationTriangle,
  FaClock,
  FaShieldAlt,
  FaDollarSign,
  FaHome,
  FaUser
} from 'react-icons/fa';

const EscrowNotifications = ({ userRole = 'buyer' }) => {
  const { escrowTransactions, getEscrowTimer } = useEscrow();
  const [notifications, setNotifications] = useState([]);
  const [showAll, setShowAll] = useState(false);

  useEffect(() => {
    generateNotifications();
  }, [escrowTransactions, userRole]);

  const generateNotifications = () => {
    const newNotifications = [];
    const now = new Date();

    escrowTransactions.forEach(transaction => {
      // Filter transactions based on user role
      const isRelevant = userRole === 'buyer' 
        ? transaction.buyerId === '1' 
        : userRole === 'vendor' 
        ? transaction.sellerId === '2'
        : true; // admin sees all

      if (!isRelevant) return;

      // Payment confirmation needed (buyer)
      if (userRole === 'buyer' && ['in_escrow', 'funded'].includes(transaction.status)) {
        const timer = getEscrowTimer(transaction.confirmationDeadline);
        if (!timer.expired) {
          newNotifications.push({
            id: `confirm-${transaction.id}`,
            type: 'warning',
            title: 'Property Confirmation Required',
            message: `You have ${timer.days} days to confirm possession of ${transaction.propertyTitle}`,
            transactionId: transaction.id,
            priority: 'high',
            timestamp: new Date(),
            action: 'confirm'
          });
        }
      }

      // Payment received (vendor)
      if (userRole === 'vendor' && transaction.status === 'funded') {
        newNotifications.push({
          id: `payment-${transaction.id}`,
          type: 'success',
          title: 'Payment Received',
          message: `Payment of ₦${transaction.amount.toLocaleString()} received for ${transaction.propertyTitle}`,
          transactionId: transaction.id,
          priority: 'high',
          timestamp: new Date(transaction.paymentDate),
          action: 'view'
        });
      }

      // Dispute filed (vendor/admin)
      if ((userRole === 'vendor' || userRole === 'admin') && transaction.status === 'disputed') {
        newNotifications.push({
          id: `dispute-${transaction.id}`,
          type: 'error',
          title: 'Dispute Filed',
          message: `A dispute has been filed for ${transaction.propertyTitle}`,
          transactionId: transaction.id,
          priority: 'urgent',
          timestamp: new Date(),
          action: userRole === 'admin' ? 'resolve' : 'view'
        });
      }

      // Auto-release triggered (buyer/vendor)
      if (transaction.status === 'auto_released') {
        newNotifications.push({
          id: `auto-release-${transaction.id}`,
          type: 'info',
          title: 'Funds Auto-Released',
          message: `Funds for ${transaction.propertyTitle} have been automatically released to vendor`,
          transactionId: transaction.id,
          priority: 'medium',
          timestamp: new Date(),
          action: 'view'
        });
      }

      // Transaction completed (both parties)
      if (transaction.status === 'completed') {
        newNotifications.push({
          id: `completed-${transaction.id}`,
          type: 'success',
          title: 'Transaction Completed',
          message: `Transaction for ${transaction.propertyTitle} has been completed successfully`,
          transactionId: transaction.id,
          priority: 'medium',
          timestamp: new Date(),
          action: 'view'
        });
      }
    });

    // Sort by priority and timestamp
    newNotifications.sort((a, b) => {
      const priorityOrder = { urgent: 0, high: 1, medium: 2, low: 3 };
      if (priorityOrder[a.priority] !== priorityOrder[b.priority]) {
        return priorityOrder[a.priority] - priorityOrder[b.priority];
      }
      return new Date(b.timestamp) - new Date(a.timestamp);
    });

    setNotifications(newNotifications);
  };

  const getNotificationIcon = (type) => {
    switch (type) {
      case 'success': return <FaCheck className="h-5 w-5 text-green-600" />;
      case 'warning': return <FaClock className="h-5 w-5 text-yellow-600" />;
      case 'error': return <FaExclamationTriangle className="h-5 w-5 text-red-600" />;
      case 'info': return <FaShieldAlt className="h-5 w-5 text-blue-600" />;
      default: return <FaBell className="h-5 w-5 text-gray-600" />;
    }
  };

  const getNotificationColor = (type) => {
    switch (type) {
      case 'success': return 'border-l-green-500 bg-green-50';
      case 'warning': return 'border-l-yellow-500 bg-yellow-50';
      case 'error': return 'border-l-red-500 bg-red-50';
      case 'info': return 'border-l-blue-500 bg-blue-50';
      default: return 'border-l-gray-500 bg-gray-50';
    }
  };

  const handleNotificationAction = (notification) => {
    // In a real app, this would navigate to the appropriate page or open a modal
    console.log('Notification action:', notification.action, notification.transactionId);
  };

  const displayedNotifications = showAll ? notifications : notifications.slice(0, 5);
  const unreadCount = notifications.filter(n => n.priority === 'urgent' || n.priority === 'high').length;

  if (notifications.length === 0) {
    return (
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <div className="text-center">
          <FaBell className="h-12 w-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No Notifications</h3>
          <p className="text-gray-600">
            {userRole === 'buyer' && 'You\'re all caught up! No pending actions required.'}
            {userRole === 'vendor' && 'No new notifications at this time.'}
            {userRole === 'admin' && 'No disputes or urgent matters require attention.'}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg border border-gray-200">
      <div className="p-6 border-b border-gray-200">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <FaBell className="h-6 w-6 text-gray-600" />
            <h3 className="text-lg font-semibold text-gray-900">Escrow Notifications</h3>
            {unreadCount > 0 && (
              <span className="bg-red-500 text-white text-xs font-bold px-2 py-1 rounded-full">
                {unreadCount}
              </span>
            )}
          </div>
          {notifications.length > 5 && (
            <button
              onClick={() => setShowAll(!showAll)}
              className="text-brand-blue hover:text-blue-700 text-sm font-medium"
            >
              {showAll ? 'Show Less' : `Show All (${notifications.length})`}
            </button>
          )}
