import React, { useState, useEffect } from 'react';
import { useEscrow } from '../contexts/EscrowContext';
import { 
  FaCheck, 
  FaClock, 
  FaExclamationTriangle,
  FaShieldAlt,
  FaDollarSign,
  FaHome,
  FaUser,
  FaCalendarAlt,
  FaFileContract,
  FaGavel,
  FaTimes,
  FaSpinner
} from 'react-icons/fa';

const EscrowStatusTracker = ({ escrowTransaction }) => {
  const { getEscrowTimer } = useEscrow();
  const [timer, setTimer] = useState(null);

  useEffect(() => {
    if (escrowTransaction.confirmationDeadline) {
      setTimer(getEscrowTimer(escrowTransaction.confirmationDeadline));

      // Update timer every minute
      const interval = setInterval(() => {
        setTimer(getEscrowTimer(escrowTransaction.confirmationDeadline));
      }, 60000);

      return () => clearInterval(interval);
    }
  }, [escrowTransaction.confirmationDeadline, getEscrowTimer]);

  const getStatusSteps = () => {
    const steps = [
      {
        id: 'payment',
        title: 'Payment Made',
        description: 'Funds transferred to escrow',
        icon: FaDollarSign,
        completed: ['funded', 'in_escrow', 'buyer_confirmed', 'auto_released', 'completed', 'disputed', 'cancelled'].includes(escrowTransaction.status)
      },
      {
        id: 'escrow',
        title: 'In Escrow',
        description: 'Funds held securely',
        icon: FaShieldAlt,
        completed: ['in_escrow', 'buyer_confirmed', 'auto_released', 'completed', 'disputed', 'cancelled'].includes(escrowTransaction.status)
      },
      {
        id: 'confirmation',
        title: 'Property Confirmation',
        description: 'Buyer confirms possession',
        icon: FaHome,
        completed: ['buyer_confirmed', 'auto_released', 'completed', 'disputed', 'cancelled'].includes(escrowTransaction.status),
        current: escrowTransaction.status === 'in_escrow' || escrowTransaction.status === 'funded'
      },
      {
        id: 'release',
        title: 'Funds Released',
        description: 'Transaction completed',
        icon: FaCheck,
        completed: ['completed', 'auto_released'].includes(escrowTransaction.status)
      }
    ];

    // Add dispute step if disputed
    if (escrowTransaction.status === 'disputed') {
      steps.push({
        id: 'dispute',
        title: 'Dispute Resolution',
        description: 'Admin reviewing case',
        icon: FaGavel,
        completed: false,
        current: true
      });
    }

    return steps;
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'pending': return 'text-yellow-600 bg-yellow-100';
      case 'funded': return 'text-blue-600 bg-blue-100';
      case 'in_escrow': return 'text-purple-600 bg-purple-100';
      case 'buyer_confirmed': return 'text-green-600 bg-green-100';
      case 'auto_released': return 'text-orange-600 bg-orange-100';
      case 'completed': return 'text-green-600 bg-green-100';
      case 'disputed': return 'text-red-600 bg-red-100';
      case 'cancelled': return 'text-gray-600 bg-gray-100';
      default: return 'text-gray-600 bg-gray-100';
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'pending': return <FaClock className="h-4 w-4" />;
      case 'funded': return <FaDollarSign className="h-4 w-4" />;
      case 'in_escrow': return <FaShieldAlt className="h-4 w-4" />;
      case 'buyer_confirmed': return <FaCheck className="h-4 w-4" />;
      case 'auto_released': return <FaCheck className="h-4 w-4" />;
      case 'completed': return <FaCheck className="h-4 w-4" />;
      case 'disputed': return <FaExclamationTriangle className="h-4 w-4" />;
      case 'cancelled': return <FaTimes className="h-4 w-4" />;
      default: return <FaClock className="h-4 w-4" />;
    }
  };

  const steps = getStatusSteps();

  return (
    <div className="bg-white rounded-lg border border-gray-200 p-6">
      {/* Header */}
      <div className="mb-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-semibold text-gray-900">Transaction Status</h3>
          <span className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-medium ${getStatusColor(escrowTransaction.status)}`}>
            {getStatusIcon(escrowTransaction.status)}
            <span className="ml-2 capitalize">{escrowTransaction.status.replace('_', ' ')}</span>
          </span>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
          <div className="flex items-center space-x-2">
            <FaHome className="text-gray-400 h-4 w-4" />
            <span className="text-gray-600">Property:</span>
            <span className="font-medium text-gray-900">{escrowTransaction.propertyTitle}</span>
          </div>
          <div className="flex items-center space-x-2">
            <FaDollarSign className="text-gray-400 h-4 w-4" />
            <span className="text-gray-600">Amount:</span>
            <span className="font-medium text-gray-900">₦{escrowTransaction.amount.toLocaleString()}</span>
          </div>
          <div className="flex items-center space-x-2">
            <FaCalendarAlt className="text-gray-400 h-4 w-4" />
            <span className="text-gray-600">Created:</span>
            <span className="font-medium text-gray-900">
              {new Date(escrowTransaction.createdAt).toLocaleDateString()}
            </span>
          </div>
        </div>
      </div>

      {/* Timer Alert */}
      {timer && !timer.expired && (escrowTransaction.status === 'in_escrow' || escrowTransaction.status === 'funded') && (
        <div className="mb-6 bg-yellow-50 border border-yellow-200 rounded-lg p-4">
          <div className="flex items-center space-x-3">
            <FaClock className="text-yellow-600 h-5 w-5" />
            <div>
              <p className="text-sm font-medium text-yellow-900">Confirmation Deadline</p>
              <p className="text-sm text-yellow-800">
                {timer.days} days, {timer.hours} hours, {timer.minutes} minutes remaining
              </p>
            </div>
          </div>
        </div>
      )}

      {timer && timer.expired && (escrowTransaction.status === 'in_escrow' || escrowTransaction.status === 'funded') && (
        <div className="mb-6 bg-red-50 border border-red-200 rounded-lg p-4">
          <div className="flex items-center space-x-3">
            <FaExclamationTriangle className="text-red-600 h-5 w-5" />
            <div>
              <p className="text-sm font-medium text-red-900">Deadline Expired</p>
              <p className="text-sm text-red-800">
                The confirmation deadline has passed. Funds will be automatically released to the vendor.
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Progress Steps */}
      <div className="space-y-4">
        {steps.map((step, index) => {
          const Icon = step.icon;
          const isLast = index === steps.length - 1;

          return (
            <div key={step.id} className="flex items-start space-x-4">
              <div className={`flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center ${
                step.completed 
                  ? 'bg-green-100 text-green-600' 
                  : step.current 
                    ? 'bg-brand-blue text-white' 
                    : 'bg-gray-100 text-gray-400'
              }`}>
                {step.completed ? (
                  <FaCheck className="h-5 w-5" />
                ) : step.current ? (
                  <FaSpinner className="h-5 w-5 animate-spin" />
                ) : (
                  <Icon className="h-5 w-5" />
                )}
              </div>

              <div className="flex-1 min-w-0">
                <div className="flex items-center justify-between">
                  <h4 className={`text-sm font-medium ${
                    step.completed || step.current ? 'text-gray-900' : 'text-gray-500'
                  }`}>
                    {step.title}
                  </h4>
                  {step.current && (
                    <span className="bg-brand-blue text-white text-xs font-medium px-2 py-1 rounded-full">
                      Current
                    </span>
                  )}
                </div>
                <p className={`text-sm ${
                  step.completed || step.current ? 'text-gray-600' : 'text-gray-400'
                }`}>
                  {step.description}
                </p>

                {/* Step-specific information */}
                {step.id === 'payment' && escrowTransaction.paymentDate && (
                  <p className="text-xs text-gray-500 mt-1">
                    Paid on {new Date(escrowTransaction.paymentDate).toLocaleDateString()}
                  </p>
                )}

                {step.id === 'confirmation' && timer && !timer.expired && (
                  <p className="text-xs text-orange-600 mt-1">
                    {timer.days}d {timer.hours}h {timer.minutes}m remaining
                  </p>
                )}

                {step.id === 'dispute' && escrowTransaction.disputeReason && (
                  <p className="text-xs text-red-600 mt-1">
                    Reason: {escrowTransaction.disputeReason.replace('_', ' ')}
                  </p>
                )}
              </div>

              {!isLast && (
                <div className={`w-px h-8 ml-5 ${
                  step.completed ? 'bg-green-200' : 'bg-gray-200'
                }`} />
              )}
            </div>
          );
        })}
      </div>

      {/* Transaction Details */}
      <div className="mt-6 pt-6 border-t border-gray-200">
        <h4 className="text-sm font-medium text-gray-900 mb-3">Transaction Details</h4>
        <div className="grid grid-cols-2 gap-4 text-sm">
          <div>
            <p className="text-gray-500">Transaction ID</p>
            <p className="font-medium text-gray-900">{escrowTransaction.id}</p>
          </div>
          <div>
            <p className="text-gray-500">Escrow Fee</p>
            <p className="font-medium text-gray-900">₦{escrowTransaction.escrowFee?.toLocaleString() || '0'}</p>
          </div>
          <div>
            <p className="text-gray-500">Payment Method</p>
            <p className="font-medium text-gray-900 capitalize">
              {escrowTransaction.paymentMethod?.replace('_', ' ') || 'N/A'}
            </p>
          </div>
          <div>
            <p className="text-gray-500">Flutterwave Reference</p>
            <p className="font-medium text-gray-900 text-xs">
              {escrowTransaction.flutterwaveReference || 'N/A'}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EscrowStatusTracker;

import React, { useState, useRef } from 'react';
import { FaUpload, FaTimes, FaImage, FaFile, FaCheck, FaExclamationTriangle } from 'react-icons/fa';
import storageService from '../services/storageService';
import toast from 'react-hot-toast';

const FileUpload = ({
  onUpload,
  onRemove,
  files = [],
  maxFiles = 5,
  maxSize = 5 * 1024 * 1024, // 5MB
  allowedTypes = ['image/jpeg', 'image/png', 'image/webp'],
  uploadPath = '',
  uploadType = 'general', // 'property_images', 'user_avatar', 'escrow_document'
  metadata = {},
  disabled = false,
  className = ''
}) => {
  const [uploading, setUploading] = useState(false);
  const [dragOver, setDragOver] = useState(false);
  const fileInputRef = useRef(null);

  const handleFileSelect = async (selectedFiles) => {
    if (disabled || uploading) return;

    const fileArray = Array.from(selectedFiles);

    // Check if adding these files would exceed maxFiles limit
    if (files.length + fileArray.length > maxFiles) {
      toast.error(`Maximum ${maxFiles} files allowed`);
      return;
    }

    // Validate each file
    const validFiles = [];
    const invalidFiles = [];

    fileArray.forEach(file => {
      const validation = storageService.validateFile(file, allowedTypes, maxSize);
      if (validation.valid) {
        validFiles.push(file);
      } else {
        invalidFiles.push({ file, errors: validation.errors });
      }
    });

    // Show validation errors
    if (invalidFiles.length > 0) {
      invalidFiles.forEach(({ file, errors }) => {
        errors.forEach(error => {
          toast.error(`${file.name}: ${error}`);
        });
      });
    }

    if (validFiles.length === 0) return;

    setUploading(true);

    try {
      let uploadResult;

      switch (uploadType) {
        case 'property_images':
          uploadResult = await storageService.uploadPropertyImages(
            validFiles, 
            metadata.propertyId, 
            metadata.userId
          );
          break;
        case 'user_avatar':
          uploadResult = await storageService.uploadUserAvatar(
            validFiles[0], 
            metadata.userId
          );
          break;
        case 'escrow_document':
          uploadResult = await storageService.uploadEscrowDocument(
            validFiles[0],
            metadata.escrowId,
            metadata.documentType,
            metadata.userId
          );
          break;
        default:
          uploadResult = await storageService.uploadMultipleFiles(
            validFiles, 
            uploadPath, 
            metadata
          );
      }

      if (uploadResult.success) {
        if (uploadType === 'user_avatar' || uploadType === 'escrow_document') {
          // Single file uploads
          onUpload && onUpload(uploadResult);
        } else {
          // Multiple file uploads
          onUpload && onUpload(uploadResult.successful);
        }
        toast.success(`${validFiles.length} file(s) uploaded successfully!`);
      } else {
        throw new Error(uploadResult.error || 'Upload failed');
      }
    } catch (error) {
      console.error('Upload error:', error);
      toast.error('Failed to upload files');
    } finally {
      setUploading(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setDragOver(false);

    if (disabled || uploading) return;

    const droppedFiles = e.dataTransfer.files;
    handleFileSelect(droppedFiles);
  };

  const handleDragOver = (e) => {
    e.preventDefault();
    if (!disabled && !uploading) {
      setDragOver(true);
    }
  };

  const handleDragLeave = (e) => {
    e.preventDefault();
    setDragOver(false);
  };

  const handleFileInputChange = (e) => {
    const selectedFiles = e.target.files;
    if (selectedFiles.length > 0) {
      handleFileSelect(selectedFiles);
    }
    // Reset input value to allow selecting the same file again
    e.target.value = '';
  };

  const handleRemoveFile = (fileIndex) => {
    if (disabled || uploading) return;
    onRemove && onRemove(fileIndex);
  };

  const openFileDialog = () => {
    if (!disabled && !uploading) {
      fileInputRef.current?.click();
    }
  };

  const getFileIcon = (file) => {
    if (file.type?.startsWith('image/')) {
      return <FaImage className="text-blue-500" />;
    }
    return <FaFile className="text-gray-500" />;
  };

  const formatFileSize = (bytes) => {
    return storageService.formatFileSize(bytes);
  };

  return (
    <div className={`file-upload-container ${className}`}>
      {/* Upload Area */}
      <div
        className={`
          relative border-2 border-dashed rounded-lg p-6 text-center transition-colors
          ${dragOver ? 'border-brand-blue bg-blue-50' : 'border-gray-300 hover:border-gray-400'}
          ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}
          ${uploading ? 'pointer-events-none' : ''}
        `}
        onDrop={handleDrop}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onClick={openFileDialog}
      >
        <input
          ref={fileInputRef}
          type="file"
          multiple={uploadType !== 'user_avatar' && uploadType !== 'escrow_document'}
          accept={allowedTypes.join(',')}
          onChange={handleFileInputChange}
          className="hidden"
          disabled={disabled || uploading}
        />

        <div className="space-y-2">
          <FaUpload className={`mx-auto text-2xl ${dragOver ? 'text-brand-blue' : 'text-gray-400'}`} />

          {uploading ? (
            <div className="space-y-2">
              <div className="text-sm text-gray-600">Uploading files...</div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div className="bg-brand-blue h-2 rounded-full animate-pulse" style={{ width: '60%' }}></div>
              </div>
            </div>
          ) : (
            <div className="space-y-1">
              <p className="text-sm font-medium text-gray-700">
                {dragOver ? 'Drop files here' : 'Click to upload or drag and drop'}
              </p>
              <p className="text-xs text-gray-500">
                {allowedTypes.includes('image/') ? 'Images' : 'Files'} up to {formatFileSize(maxSize)}
              </p>
              {maxFiles > 1 && (
                <p className="text-xs text-gray-500">
                  Maximum {maxFiles} files
                </p>
              )}
            </div>
          )}
        </div>
      </div>

      {/* File List */}
      {files.length > 0 && (
        <div className="mt-4 space-y-2">
          <h4 className="text-sm font-medium text-gray-700">Uploaded Files:</h4>
          <div className="space-y-2">
            {files.map((file, index) => (
              <div
                key={index}
                className="flex items-center justify-between p-3 bg-gray-50 rounded-lg"
              >
                <div className="flex items-center space-x-3">
                  {getFileIcon(file)}
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-900 truncate">
                      {file.name || file.fileName}
                    </p>
                    <p className="text-xs text-gray-500">
                      {formatFileSize(file.size || file.fileSize)}
                    </p>
                  </div>
                </div>

                <div className="flex items-center space-x-2">
                  {file.url && (
                    <a
                      href={file.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-brand-blue hover:text-brand-orange text-sm"
                    >
                      View
                    </a>
                  )}

                  {!disabled && !uploading && (
                    <button
                      onClick={() => handleRemoveFile(index)}
                      className="text-red-500 hover:text-red-700 p-1"
                    >
                      <FaTimes className="text-sm" />
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Upload Status */}
      {uploading && (
        <div className="mt-4 p-3 bg-blue-50 border border-blue-200 rounded-lg">
          <div className="flex items-center space-x-2">
            <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-brand-blue"></div>
            <span className="text-sm text-blue-700">Uploading files...</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default FileUpload;

import React, { useState, useRef, useCallback } from 'react';
import { FiUpload, FiX, FiFile, FiImage, FiVideo, FiCheckCircle, FiAlertCircle } from 'react-icons/fi';
import apiClient from '../services/apiClient';
import toast from 'react-hot-toast';
// Use centralized apiClient for uploads and deletes (handles Authorization + refresh)

/**
 * Enhanced File Upload Component
 * Supports images, videos, and documents with progress tracking
 */
const FileUploadEnhanced = ({
  uploadType = 'images', // 'images', 'videos', 'documents', 'avatar'
  propertyId = null,
  maxFiles = 10,
  maxSize = 10, // MB
  onUploadComplete,
  onUploadError,
  existingFiles = [],
  showPreview = true,
  multiple = true
}) => {
  const [files, setFiles] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState({});
  const [uploadedFiles, setUploadedFiles] = useState(existingFiles);
  const fileInputRef = useRef(null);

  // Determine accepted file types
  const getAcceptedTypes = () => {
    switch (uploadType) {
      case 'images':
        return 'image/jpeg,image/jpg,image/png,image/webp,image/gif';
      case 'videos':
        return 'video/mp4,video/quicktime,video/x-msvideo,video/webm';
      case 'documents':
        return 'application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document,text/plain';
      case 'avatar':
        return 'image/jpeg,image/jpg,image/png,image/webp';
      default:
        return '*/*';
    }
  };

  // Validate file
  const validateFile = (file) => {
    const maxSizeBytes = maxSize * 1024 * 1024;
    
    if (file.size > maxSizeBytes) {
      return `File ${file.name} exceeds maximum size of ${maxSize}MB`;
    }

    const acceptedTypes = getAcceptedTypes().split(',');
    if (!acceptedTypes.includes(file.type) && !acceptedTypes.includes('*/*')) {
      return `File ${file.name} has invalid type`;
    }

    return null;
  };

  // Handle file selection
  const handleFileSelect = (event) => {
    const selectedFiles = Array.from(event.target.files);
    
    // Validate total file count
    if (files.length + selectedFiles.length > maxFiles) {
      toast.error(`Maximum ${maxFiles} files allowed`);
      return;
    }

    // Validate each file
    const validFiles = [];
    for (const file of selectedFiles) {
      const error = validateFile(file);
      if (error) {
        toast.error(error);
        continue;
      }
      validFiles.push({
        file,
        id: `${Date.now()}-${Math.random()}`,
        preview: file.type.startsWith('image/') ? URL.createObjectURL(file) : null,
        name: file.name,
        size: file.size,
        type: file.type,
        status: 'pending'
      });
    }

    setFiles(prev => [...prev, ...validFiles]);
  };

  // Remove file from list
  const removeFile = (fileId) => {
    setFiles(prev => {
      const file = prev.find(f => f.id === fileId);
      if (file?.preview) {
        URL.revokeObjectURL(file.preview);
      }
      return prev.filter(f => f.id !== fileId);
    });
  };

  // Delete uploaded file
  const deleteUploadedFile = async (publicId, fileIndex) => {
    try {
      await apiClient.delete(`/upload/${encodeURIComponent(publicId)}`);

      setUploadedFiles(prev => prev.filter((_, index) => index !== fileIndex));
      toast.success('File deleted successfully');
    } catch (error) {
      console.error('Error deleting file:', error);
      toast.error('Failed to delete file');
    }
  };

  // Upload files
  const uploadFiles = useCallback(async () => {
    if (files.length === 0) {
      toast.error('Please select files to upload');
      return;
    }

    if (!propertyId && uploadType !== 'avatar') {
      toast.error('Property ID is required');
      return;
    }

    setUploading(true);
    const formData = new FormData();

    // Determine endpoint and field name
    let endpoint = '';
    let fieldName = '';

    switch (uploadType) {
      case 'images':
        endpoint = `/api/upload/property/${propertyId}/images`;
        fieldName = 'images';
        break;
      case 'videos':
        endpoint = `/api/upload/property/${propertyId}/videos`;
        fieldName = 'videos';
        break;
      case 'documents':
        endpoint = `/api/upload/property/${propertyId}/documents`;
        fieldName = 'documents';
        break;
      case 'avatar':
        endpoint = '/api/upload/avatar';
        fieldName = 'avatar';
        break;
      default:
        toast.error('Invalid upload type');
        setUploading(false);
        return;
    }

    // Append files to form data
    if (uploadType === 'avatar') {
      formData.append(fieldName, files[0].file);
    } else {
      files.forEach(fileObj => {
        formData.append(fieldName, fileObj.file);
      });
    }

    try {
      const relativeEndpoint = endpoint.replace(/^\/api/, '');
      const response = await apiClient.post(relativeEndpoint, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
        onUploadProgress: (progressEvent) => {
          const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
          setUploadProgress(prev => ({
            ...prev,
            total: percentCompleted
          }));
        }
      });

      if (response.data.success) {
        const newFiles = Array.isArray(response.data.data.uploaded) 
          ? response.data.data.uploaded 
          : [response.data.data];

        setUploadedFiles(prev => [...prev, ...newFiles]);
        setFiles([]);
        setUploadProgress({});
        toast.success(response.data.message || 'Files uploaded successfully');

        if (onUploadComplete) {
          onUploadComplete(newFiles);
        }
      } else {
        throw new Error(response.data.message || 'Upload failed');
      }
    } catch (error) {
      console.error('Upload error:', error);
      const message = error.response?.data?.message || error.message || 'Failed to upload files';
      toast.error(message);

      if (onUploadError) {
        onUploadError(error);
      }
    } finally {
      setUploading(false);
    }
  }, [files, propertyId, uploadType, onUploadComplete, onUploadError]);

  // Format file size
  const formatFileSize = (bytes) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return Math.round(bytes / Math.pow(k, i) * 100) / 100 + ' ' + sizes[i];
  };

  // Get file icon
  const getFileIcon = (type) => {
    if (type.startsWith('image/')) return <FiImage className="text-blue-500" size={24} />;
    if (type.startsWith('video/')) return <FiVideo className="text-purple-500" size={24} />;
    return <FiFile className="text-gray-500" size={24} />;
  };

  return (
    <div className="w-full space-y-4">
      {/* File Input Area */}
      <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center hover:border-blue-500 transition-colors">
        <input
          ref={fileInputRef}
          type="file"
          accept={getAcceptedTypes()}
          multiple={multiple && uploadType !== 'avatar'}
          onChange={handleFileSelect}
          className="hidden"
        />
        
        <FiUpload className="mx-auto text-gray-400 mb-4" size={48} />
        
        <p className="text-gray-600 mb-2">
          {uploadType === 'avatar' ? 'Upload your avatar' : `Upload ${uploadType}`}
        </p>
        
        <p className="text-sm text-gray-500 mb-4">
          Max {maxFiles} file{maxFiles > 1 ? 's' : ''} • {maxSize}MB per file
        </p>
        
        <button
          type="button"
          onClick={() => fileInputRef.current?.click()}
          className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          disabled={uploading}
        >
          Choose Files
        </button>
      </div>

      {/* Selected Files List */}
      {files.length > 0 && (
        <div className="space-y-2">
          <h3 className="font-semibold text-gray-700">Selected Files</h3>
          
          {files.map(fileObj => (
            <div key={fileObj.id} className="flex items-center gap-4 p-4 bg-gray-50 rounded-lg">
              {showPreview && fileObj.preview ? (
                <img
                  src={fileObj.preview}
                  alt={fileObj.name}
                  className="w-16 h-16 object-cover rounded"
                />
              ) : (
                <div className="w-16 h-16 flex items-center justify-center bg-gray-200 rounded">
                  {getFileIcon(fileObj.type)}
                </div>
              )}
              
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-gray-900 truncate">{fileObj.name}</p>
                <p className="text-xs text-gray-500">{formatFileSize(fileObj.size)}</p>
              </div>
              
              <button
                type="button"
                onClick={() => removeFile(fileObj.id)}
                className="text-red-500 hover:text-red-700"
                disabled={uploading}
              >
                <FiX size={20} />
              </button>
            </div>
          ))}

          {/* Upload Button */}
          <div className="flex gap-2">
            <button
              type="button"
              onClick={uploadFiles}
              disabled={uploading}
              className="flex-1 px-6 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors disabled:bg-gray-400 disabled:cursor-not-allowed"
            >
              {uploading ? (
                <>
                  <span className="inline-block animate-spin mr-2">⏳</span>
                  Uploading... {uploadProgress.total || 0}%
                </>
              ) : (
                'Upload Files'
              )}
            </button>
            
            <button
              type="button"
              onClick={() => setFiles([])}
              disabled={uploading}
              className="px-6 py-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:bg-gray-100 disabled:cursor-not-allowed"
            >
              Clear
            </button>
          </div>
        </div>
      )}

      {/* Uploaded Files List */}
      {uploadedFiles.length > 0 && (
        <div className="space-y-2">
          <h3 className="font-semibold text-gray-700 flex items-center gap-2">
            <FiCheckCircle className="text-green-500" />
            Uploaded Files ({uploadedFiles.length})
          </h3>
          
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
            {uploadedFiles.map((file, index) => (
              <div key={index} className="relative group">
                {file.thumbnail || file.url ? (
                  <img
                    src={file.thumbnail || file.url}
                    alt={file.originalName || `Upload ${index + 1}`}
                    className="w-full h-32 object-cover rounded-lg"
                  />
                ) : (
                  <div className="w-full h-32 flex items-center justify-center bg-gray-200 rounded-lg">
                    {getFileIcon(file.format || 'file')}
                  </div>
                )}
                
                <button
                  type="button"
                  onClick={() => deleteUploadedFile(file.publicId, index)}
                  className="absolute top-2 right-2 p-1 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-600"
                  title="Delete file"
                >
                  <FiX size={16} />
                </button>
                
                <div className="absolute bottom-0 left-0 right-0 bg-black bg-opacity-50 text-white text-xs p-2 rounded-b-lg opacity-0 group-hover:opacity-100 transition-opacity truncate">
                  {formatFileSize(file.size)}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default FileUploadEnhanced;

import React, { useState, useEffect, useRef } from 'react';
import { FaSearch, FaTimes, FaBuilding, FaChartLine, FaUser, FaMapMarkerAlt } from 'react-icons/fa';
import { useProperty } from '../contexts/PropertyContext';
import { useInvestment } from '../contexts/InvestmentContext';
import { useAuth } from '../contexts/AuthContext';

const GlobalSearch = ({ isOpen, onClose, onResultClick }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState({
    properties: [],
    investments: [],
    users: []
  });
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('all');
  const searchRef = useRef(null);
  const inputRef = useRef(null);

  const { searchProperties } = useProperty();
  const { searchInvestments } = useInvestment();
  const { user } = useAuth();

  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        onClose();
      }
    };

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [isOpen, onClose]);

  useEffect(() => {
    const performSearch = async () => {
      if (!query.trim()) {
        setResults({ properties: [], investments: [], users: [] });
        return;
      }

      setIsLoading(true);
      try {
        const searchResults = {
          properties: [],
          investments: [],
          users: []
        };

        if (activeTab === 'all' || activeTab === 'properties') {
          const propertyResults = searchProperties ? searchProperties(query, {}) : [];
          searchResults.properties = Array.isArray(propertyResults) ? propertyResults.slice(0, 5) : [];
        }

        if (activeTab === 'all' || activeTab === 'investments') {
          const investmentResults = searchInvestments ? searchInvestments(query, {}) : [];
          searchResults.investments = Array.isArray(investmentResults) ? investmentResults.slice(0, 5) : [];
        }

        if (activeTab === 'all' || activeTab === 'users') {
          const mockUsers = [
            { id: '1', name: 'John Doe', email: 'john@example.com', role: 'buyer', avatar: null },
            { id: '2', name: 'Admin User', email: 'admin@propertyark.com', role: 'admin', avatar: null },
            { id: '3', name: 'Onyedikachi Akoma', email: 'onyedikachi@example.com', role: 'vendor', avatar: null }
          ];

          searchResults.users = mockUsers.filter(user => 
            user.name.toLowerCase().includes(query.toLowerCase()) ||
            user.email.toLowerCase().includes(query.toLowerCase())
          ).slice(0, 5);
        }

        setResults(searchResults);
      } catch (error) {
        console.error('Search error:', error);
        setResults({ properties: [], investments: [], users: [] });
      } finally {
        setIsLoading(false);
      }
    };

    const debounceTimer = setTimeout(performSearch, 300);
    return () => clearTimeout(debounceTimer);
  }, [query, activeTab, searchProperties, searchInvestments]);

  const handleResultClick = (type, item) => {
    onResultClick(type, item);
    onClose();
  };

  const formatPrice = (price) => {
    return new Intl.NumberFormat('en-NG', {
      style: 'currency',
      currency: 'NGN',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(price);
  };

  const totalResults = (results?.properties?.length || 0) + (results?.investments?.length || 0) + (results?.users?.length || 0);

  useEffect(() => {
    const handleEscape = (event) => {
      if (event.key === 'Escape' && isOpen) {
        onClose();
      }
    };

    if (isOpen) {
      document.addEventListener('keydown', handleEscape);
      return () => document.removeEventListener('keydown', handleEscape);
    }
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center pt-20 pointer-events-none">
      <div 
        className="absolute inset-0 bg-black bg-opacity-20 pointer-events-auto"
        onClick={onClose}
      />

      <div 
        ref={searchRef} 
        className="relative bg-white rounded-lg shadow-2xl w-full max-w-2xl mx-4 pointer-events-auto transform transition-all duration-200 ease-out opacity-100"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="p-4 border-b border-gray-200">
          <div className="flex items-center space-x-3">
            <FaSearch className="text-gray-400" />
            <input
              ref={inputRef}
              type="text"
              placeholder="Search properties, investments, users..."
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              className="flex-1 outline-none text-lg"
            />
            <button
              onClick={onClose}
              className="p-2 hover:bg-gray-100 rounded-full transition-colors"
              aria-label="Close search"
            >
              <FaTimes className="text-gray-400" />
            </button>
          </div>
        </div>

        <div className="flex border-b border-gray-200">
          {[
            { key: 'all', label: 'All', count: totalResults },
            { key: 'properties', label: 'Properties', count: results?.properties?.length || 0 },
            { key: 'investments', label: 'Investments', count: results?.investments?.length || 0 },
            { key: 'users', label: 'Users', count: results?.users?.length || 0 }
          ].map(tab => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
                activeTab === tab.key
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              {tab.label} {tab.count > 0 && `(${tab.count})`}
            </button>
          ))}
        </div>

        <div className="max-h-[60vh] overflow-y-auto">
          {isLoading ? (
            <div className="p-8 text-center">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500 mx-auto"></div>
              <p className="mt-2 text-gray-500">Searching...</p>
            </div>
          ) : query.trim() ? (
            <div className="p-4">
              {(activeTab === 'all' || activeTab === 'properties') && (results?.properties?.length || 0) > 0 && (
                <div className="mb-6">
                  <h3 className="text-sm font-semibold text-gray-700 mb-3 flex items-center">
                    <FaBuilding className="mr-2" />
                    Properties ({(results?.properties?.length || 0)})
                  </h3>
                  <div className="space-y-2">
                    {(results?.properties || []).map(property => (
                      <div
                        key={property.id}
                        onClick={() => handleResultClick('property', property)}
                        className="p-3 hover:bg-gray-50 rounded-lg cursor-pointer transition-colors"
                      >
                        <div className="flex items-start space-x-3">
                          <div className="w-12 h-12 bg-gray-200 rounded-lg flex items-center justify-center">
                            {property.images?.[0] ? (
                              <img
                                src={property.images[0]}
                                alt={property.title}
                                className="w-full h-full object-cover rounded-lg"
                              />
                            ) : (
                              <FaBuilding className="text-gray-400" />
                            )}
                          </div>
                          <div className="flex-1 min-w-0">
                            <h4 className="font-medium text-gray-900 truncate">{property.title}</h4>
                            <p className="text-sm text-gray-500 flex items-center">
                              <FaMapMarkerAlt className="mr-1" />
                              {property.location?.address || property.address}
                            </p>
                            <p className="text-sm font-semibold text-blue-600">
                              {formatPrice(property.price)}
                            </p>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {(activeTab === 'all' || activeTab === 'investments') && (results?.investments?.length || 0) > 0 && (
                <div className="mb-6">
                  <h3 className="text-sm font-semibold text-gray-700 mb-3 flex items-center">
                    <FaChartLine className="mr-2" />
                    Investments ({(results?.investments?.length || 0)})
                  </h3>
                  <div className="space-y-2">
                    {(results?.investments || []).map(investment => (
                      <div
                        key={investment.id}
                        onClick={() => handleResultClick('investment', investment)}
                        className="p-3 hover:bg-gray-50 rounded-lg cursor-pointer transition-colors"
                      >
                        <div className="flex items-start space-x-3">
                          <div className="w-12 h-12 bg-gray-200 rounded-lg flex items-center justify-center">
                            {investment.images?.[0] ? (
                              <img
                                src={investment.images[0]}
                                alt={investment.title}
                                className="w-full h-full object-cover rounded-lg"
                              />
                            ) : (
                              <FaChartLine className="text-gray-400" />
                            )}
                          </div>
                          <div className="flex-1 min-w-0">
                            <h4 className="font-medium text-gray-900 truncate">{investment.title}</h4>
                            <p className="text-sm text-gray-500 flex items-center">
                              <FaMapMarkerAlt className="mr-1" />
                              {investment.location?.city}, {investment.location?.state}
                            </p>
                            <div className="flex items-center space-x-4 text-sm">
                              <span className="text-green-600 font-semibold">
                                {investment.expectedReturn}% ROI
                              </span>
                              <span className="text-gray-500">
                                Min: {formatPrice(investment.minimumInvestment)}
                              </span>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {(activeTab === 'all' || activeTab === 'users') && (results?.users?.length || 0) > 0 && (
                <div className="mb-6">
                  <h3 className="text-sm font-semibold text-gray-700 mb-3 flex items-center">
                    <FaUser className="mr-2" />
                    Users ({(results?.users?.length || 0)})
                  </h3>
                  <div className="space-y-2">
                    {(results?.users || []).map(user => (
                      <div
                        key={user.id}
                        onClick={() => handleResultClick('user', user)}
                        className="p-3 hover:bg-gray-50 rounded-lg cursor-pointer transition-colors"
                      >
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 bg-gray-200 rounded-full flex items-center justify-center">
                            {user.avatar ? (
                              <img
                                src={user.avatar}
                                alt={user.name}
                                className="w-full h-full object-cover rounded-full"
                              />
                            ) : (
                              <FaUser className="text-gray-400" />
                            )}
                          </div>
                          <div className="flex-1 min-w-0">
                            <h4 className="font-medium text-gray-900">{user.name}</h4>
                            <p className="text-sm text-gray-500">{user.email}</p>
                            <span className="inline-block px-2 py-1 text-xs bg-blue-100 text-blue-800 rounded-full">
                              {user.role}
                            </span>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {totalResults === 0 && (
                <div className="text-center py-8">
                  <FaSearch className="mx-auto text-gray-300 text-4xl mb-3" />
                  <p className="text-gray-500">No results found for "{query}"</p>
                  <p className="text-sm text-gray-400 mt-1">Try different keywords or check spelling</p>
                </div>
              )}
            </div>
          ) : (
            <div className="p-8 text-center">
              <FaSearch className="mx-auto text-gray-300 text-4xl mb-3" />
              <p className="text-gray-500">Start typing to search...</p>
              <p className="text-sm text-gray-400 mt-1">Search across properties, investments, and users</p>
            </div>
          )}
        </div>

        {totalResults > 0 && (
          <div className="p-3 border-t border-gray-200 bg-gray-50">
            <div className="flex items-center justify-between text-sm text-gray-500">
              <span>{totalResults} result{totalResults !== 1 ? 's' : ''} found</span>
              <span className="text-xs">Press <kbd className="px-1.5 py-0.5 bg-white border border-gray-300 rounded text-xs">Esc</kbd> to close</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default GlobalSearch;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { FaMapMarkerAlt, FaTimes, FaExclamationTriangle } from 'react-icons/fa';
import { loadGoogleMapsAPI, isGoogleMapsLoaded, initializeGoogleMapsServices } from '../utils/googleMapsLoader';

const GoogleMapsAutocomplete = ({ 
  value, 
  onChange, 
  onPlaceSelect,
  placeholder = "Enter address...",
  className = "",
  error = false
}) => {
  const [suggestions, setSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isGoogleMapsAvailable, setIsGoogleMapsAvailable] = useState(true);
  const [memorySuggestions, setMemorySuggestions] = useState([]);
  const inputRef = useRef(null);
  const suggestionsRef = useRef(null);
  const autocompleteService = useRef(null);
  const placesService = useRef(null);
  const debounceTimer = useRef(null);
  const requestId = useRef(0);

  // Cache for frequently used addresses
  const addressCache = useRef(new Map());
  const maxCacheSize = 50;

  // Address memory management
  const getAddressMemory = () => {
    try {
      const stored = localStorage.getItem('addressMemory');
      return stored ? JSON.parse(stored) : [];
    } catch (error) {
      console.error('Error loading address memory:', error);
      return [];
    }
  };

  const saveAddressToMemory = useCallback((address) => {
    try {
      const memory = getAddressMemory();
      const newMemory = [
        { address, timestamp: Date.now() },
        ...memory.filter(item => item.address !== address)
      ].slice(0, 10); // Keep only last 10 addresses

      localStorage.setItem('addressMemory', JSON.stringify(newMemory));
      return newMemory;
    } catch (error) {
      console.error('Error saving address to memory:', error);
      return [];
    }
  }, []);

  const getMemorySuggestions = useCallback((input) => {
    if (!input || input.length < 2) return [];

    const memory = getAddressMemory();
    return memory
      .filter(item => 
        item.address.toLowerCase().includes(input.toLowerCase())
      )
      .slice(0, 5); // Show max 5 memory suggestions
  }, []);

  useEffect(() => {
    // Initialize Google Maps services (API should already be preloaded)
    const initializeServices = () => {
      if (window.google && window.google.maps && initializeGoogleMapsServices()) {
        // Check if places API is available
        if (window.google.maps.places) {
          // Use the new AutocompleteSuggestion API if available, otherwise fallback
          if (window.google.maps.places.AutocompleteSuggestion) {
            try {
              autocompleteService.current = new window.google.maps.places.AutocompleteSuggestion();
            } catch (error) {
              console.log('AutocompleteSuggestion not available, using AutocompleteService');
              autocompleteService.current = new window.google.maps.places.AutocompleteService();
            }
          } else {
            // Fallback to AutocompleteService for backward compatibility
            autocompleteService.current = new window.google.maps.places.AutocompleteService();
          }

          // Use the new Place API if available, otherwise fallback
          if (window.google.maps.places.Place) {
            try {
              placesService.current = new window.google.maps.places.Place();
            } catch (error) {
              console.log('Place API not available, using PlacesService');
              placesService.current = new window.google.maps.places.PlacesService(
                document.createElement('div')
              );
            }
          } else {
            // Fallback to PlacesService for backward compatibility
            placesService.current = new window.google.maps.places.PlacesService(
              document.createElement('div')
            );
          }
        } else {
          console.error('Google Maps Places API not available');
        }
      }
    };

    // Try to initialize immediately if already loaded
    if (isGoogleMapsLoaded()) {
      initializeServices();
    } else {
      // Fallback: load API if not already loaded
      const apiKey = process.env.REACT_APP_GOOGLE_MAPS_API_KEY || 'YOUR_GOOGLE_MAPS_API_KEY';

      // Only attempt to load if we have a real API key
      if (apiKey && apiKey !== 'YOUR_GOOGLE_MAPS_API_KEY') {
        loadGoogleMapsAPI(apiKey).then(initializeServices).catch((error) => {
          console.error('Failed to load Google Maps API:', error);
          // Set a flag to disable autocomplete functionality
          autocompleteService.current = null;
          placesService.current = null;
          setIsGoogleMapsAvailable(false);
        });
      } else {
        // Silently disable autocomplete without console warning
        // Set a flag to disable autocomplete functionality
        autocompleteService.current = null;
        placesService.current = null;
        setIsGoogleMapsAvailable(false);
      }
    }
  }, []);

  // Optimized search with caching and debouncing
  const getPlacePredictionsOptimized = useCallback((input) => {
    const currentRequestId = ++requestId.current;

    // Get memory suggestions first
    const memorySuggestions = getMemorySuggestions(input);
    setMemorySuggestions(memorySuggestions);

    // Check cache first
    const cacheKey = input.toLowerCase().trim();
    if (addressCache.current.has(cacheKey)) {
      const cachedResults = addressCache.current.get(cacheKey);
      setSuggestions(cachedResults);
      setShowSuggestions(true);
      setIsLoading(false);
      return;
    }

    // Check if services are available
    if (!autocompleteService.current || !window.google?.maps?.places) {
        // Silently handle unavailable Google Maps services
      setIsLoading(false);
      setSuggestions([]);
      setShowSuggestions(memorySuggestions.length > 0);
      return;
    }

    const request = {
      input: input,
      types: ['address'],
      componentRestrictions: { country: 'ng' }
    };

      // Use the new API if available, otherwise fallback to the old one
      if (autocompleteService.current.getPlacePredictions) {
        // Old API method
        autocompleteService.current.getPlacePredictions(request, (predictions, status) => {
          // Only process if this is still the latest request
          if (currentRequestId !== requestId.current) return;

          setIsLoading(false);
          if (status === window.google.maps.places.PlacesServiceStatus.OK && predictions) {
            // Cache the results
            if (addressCache.current.size >= maxCacheSize) {
              const firstKey = addressCache.current.keys().next().value;
              addressCache.current.delete(firstKey);
            }
            addressCache.current.set(cacheKey, predictions);

            setSuggestions(predictions);
            setShowSuggestions(true);
          } else {
            setSuggestions([]);
            setShowSuggestions(false);
          }
        });
      } else if (autocompleteService.current.getSuggestions) {
        // New API method
        autocompleteService.current.getSuggestions(request).then((predictions) => {
          // Only process if this is still the latest request
          if (currentRequestId !== requestId.current) return;

          setIsLoading(false);
          if (predictions && predictions.length > 0) {
            // Cache the results
            if (addressCache.current.size >= maxCacheSize) {
              const firstKey = addressCache.current.keys().next().value;
              addressCache.current.delete(firstKey);
            }
            addressCache.current.set(cacheKey, predictions);

            setSuggestions(predictions);
            setShowSuggestions(true);
          } else {
            setSuggestions([]);
            setShowSuggestions(false);
          }
        }).catch((error) => {
          console.error('Autocomplete error:', error);
          setIsLoading(false);
          setSuggestions([]);
          setShowSuggestions(false);
        });
      }
  }, []);

  const handleInputChange = useCallback((e) => {
    const inputValue = e.target.value;
    onChange(inputValue);

    // Clear previous debounce timer
    if (debounceTimer.current) {
      clearTimeout(debounceTimer.current);
    }

    if (inputValue.length > 2) {
      setIsLoading(true);
      // Debounce the API call by 300ms
      debounceTimer.current = setTimeout(() => {
        getPlacePredictionsOptimized(inputValue);
      }, 300);
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
      setIsLoading(false);
    }
  }, [onChange, getPlacePredictionsOptimized]);

  // Save address to memory when user finishes typing (on blur)
  const handleInputBlur = useCallback((e) => {
    const inputValue = e.target.value.trim();
    if (inputValue.length > 5) { // Only save meaningful addresses
      saveAddressToMemory(inputValue);
    }
    // Defer hiding suggestions using local logic to avoid referencing before init
    setTimeout(() => {
      if (!suggestionsRef.current?.contains(document.activeElement)) {
        setShowSuggestions(false);
      }
    }, 200);
  }, []);

  // Optimized place selection with caching
  const handleSuggestionClick = useCallback((suggestion) => {
    if (!placesService.current || !window.google?.maps?.places) {
      console.warn('Google Maps places service not available');
      return;
    }

    // Cancel any pending debounced requests
    if (debounceTimer.current) {
      clearTimeout(debounceTimer.current);
    }

    const request = {
      placeId: suggestion.place_id,
      fields: ['formatted_address', 'geometry', 'address_components', 'url']
    };

    // Use the new API if available, otherwise fallback to the old one
    if (placesService.current.getDetails) {
      // Old API method
      placesService.current.getDetails(request, (place, status) => {
        if (status === window.google.maps.places.PlacesServiceStatus.OK && place) {
          // Extract address components
          const addressComponents = place.address_components || [];
          const city = addressComponents.find(component => 
            component.types.includes('locality')
          )?.long_name || '';
          const state = addressComponents.find(component => 
            component.types.includes('administrative_area_level_1')
          )?.long_name || '';
          const zipCode = addressComponents.find(component => 
            component.types.includes('postal_code')
          )?.long_name || '';

          // Call the onPlaceSelect callback with all the data
          onPlaceSelect({
            address: place.formatted_address,
            city: city,
            state: state,
            zipCode: zipCode,
            coordinates: {
              latitude: place.geometry?.location?.lat(),
              longitude: place.geometry?.location?.lng()
            },
            googleMapsUrl: place.url || `https://www.google.com/maps/place/?q=place_id:${suggestion.place_id}`
          });

          // Save to address memory
          saveAddressToMemory(place.formatted_address);

          // Update the input value
          onChange(place.formatted_address);
          setShowSuggestions(false);
          setSuggestions([]);
        }
      });
    } else if (placesService.current.fetchFields) {
      // New API method
      placesService.current.fetchFields(request).then((place) => {
        if (place) {
          // Extract address components
          const addressComponents = place.address_components || [];
          const city = addressComponents.find(component => 
            component.types.includes('locality')
          )?.long_name || '';
          const state = addressComponents.find(component => 
            component.types.includes('administrative_area_level_1')
          )?.long_name || '';
          const zipCode = addressComponents.find(component => 
            component.types.includes('postal_code')
          )?.long_name || '';

          // Call the onPlaceSelect callback with all the data
          onPlaceSelect({
            address: place.formatted_address,
            city: city,
            state: state,
            zipCode: zipCode,
            coordinates: {
              latitude: place.geometry?.location?.lat(),
              longitude: place.geometry?.location?.lng()
            },
            googleMapsUrl: place.url || `https://www.google.com/maps/place/?q=place_id:${suggestion.place_id}`
          });

          // Save to address memory
          saveAddressToMemory(place.formatted_address);

          // Update the input value
          onChange(place.formatted_address);
          setShowSuggestions(false);
          setSuggestions([]);
        }
      }).catch((error) => {
        console.error('Place details error:', error);
      });
    }
  }, [onPlaceSelect, onChange]);


  const handleMemorySuggestionClick = useCallback((memorySuggestion) => {
    // Clear debounce timer
    if (debounceTimer.current) {
      clearTimeout(debounceTimer.current);
    }

    // Update the input value
    onChange(memorySuggestion.address);

    // Call the onPlaceSelect callback with the memory data
    onPlaceSelect({
      address: memorySuggestion.address,
      city: '',
      state: '',
      zipCode: '',
      coordinates: {
        latitude: null,
        longitude: null
      },
      googleMapsUrl: ''
    });

    setShowSuggestions(false);
    setSuggestions([]);
    setMemorySuggestions([]);
  }, [onChange, onPlaceSelect]);

  const handleClearInput = useCallback(() => {
    // Clear debounce timer
    if (debounceTimer.current) {
      clearTimeout(debounceTimer.current);
    }
    onChange('');
    setSuggestions([]);
    setShowSuggestions(false);
    setIsLoading(false);
    inputRef.current?.focus();
  }, [onChange]);

  const handleBlur = useCallback((e) => {
    // Delay hiding suggestions to allow clicking on them
    setTimeout(() => {
      if (!suggestionsRef.current?.contains(document.activeElement)) {
        setShowSuggestions(false);
      }
    }, 200);
  }, []);

  const handleFocus = useCallback(() => {
    if (suggestions.length > 0) {
      setShowSuggestions(true);
    }
  }, [suggestions.length]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (debounceTimer.current) {
        clearTimeout(debounceTimer.current);
      }
    };
  }, []);

  return (
    <div className="relative">
      <div className="relative">
        <input
          ref={inputRef}
          type="text"
          value={value}
          onChange={handleInputChange}
          onBlur={handleInputBlur}
          onFocus={handleFocus}
          className={`w-full pl-12 pr-12 py-4 border-2 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all duration-300 ${
            error ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-blue-500'
          }`}
          placeholder={isGoogleMapsAvailable ? placeholder : "Enter address manually (autocomplete disabled)"}
        />
        <FaMapMarkerAlt className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400 text-lg" />
        {value && (
          <button
            type="button"
            onClick={handleClearInput}
            className="absolute right-4 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600 transition-colors"
          >
            <FaTimes className="text-sm" />
          </button>
        )}
      </div>

      {/* Loading indicator */}
      {isLoading && (
        <div className="absolute top-full left-0 right-0 bg-white border border-gray-200 rounded-b-xl shadow-lg z-50">
          <div className="p-4 text-center">
            <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-500 mx-auto"></div>
            <p className="text-sm text-gray-600 mt-2">Searching addresses...</p>
          </div>
        </div>
        )}

        {/* Google Maps not available message */}
        {!isGoogleMapsAvailable && (
          <div className="mt-2 p-3 bg-yellow-50 border border-yellow-200 rounded-lg">
            <p className="text-sm text-yellow-700">
              <FaExclamationTriangle className="inline mr-1" />
              Google Maps autocomplete is disabled. Please enter the address manually.
            </p>
          </div>
        )}

        {/* Suggestions dropdown */}
        {(showSuggestions && (suggestions.length > 0 || memorySuggestions.length > 0)) && (
        <div 
          ref={suggestionsRef}
          className="absolute top-full left-0 right-0 bg-white border border-gray-200 rounded-b-xl shadow-lg z-50 max-h-60 overflow-y-auto"
        >
          {/* Memory Suggestions */}
          {memorySuggestions.length > 0 && (
            <>
              <div className="px-4 py-2 bg-gray-50 border-b border-gray-200">
                <p className="text-xs font-semibold text-gray-600 uppercase tracking-wide">Recent Addresses</p>
              </div>
              {memorySuggestions.map((memorySuggestion, index) => (
                <button
                  key={`memory-${index}`}
                  type="button"
                  onClick={() => handleMemorySuggestionClick(memorySuggestion)}
                  className="w-full px-4 py-3 text-left hover:bg-gray-50 border-b border-gray-100 last:border-b-0 transition-colors focus:outline-none focus:bg-gray-50"
                >
                  <div className="flex items-start space-x-3">
                    <FaMapMarkerAlt className="text-green-500 text-sm mt-1 flex-shrink-0" />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-gray-900 truncate">
                        {memorySuggestion.address}
                      </p>
                      <p className="text-xs text-gray-500">
                        Previously used
                      </p>
                    </div>
                  </div>
                </button>
              ))}
              {suggestions.length > 0 && (
                <div className="px-4 py-2 bg-gray-50 border-b border-gray-200">
                  <p className="text-xs font-semibold text-gray-600 uppercase tracking-wide">Google Maps Suggestions</p>
                </div>
              )}
            </>
          )}

          {/* Google Maps Suggestions */}
          {suggestions.slice(0, 8).map((suggestion) => (
            <button
              key={suggestion.place_id}
              type="button"
              onClick={() => handleSuggestionClick(suggestion)}
              className="w-full px-4 py-3 text-left hover:bg-gray-50 border-b border-gray-100 last:border-b-0 transition-colors focus:outline-none focus:bg-gray-50"
            >
              <div className="flex items-start space-x-3">
                <FaMapMarkerAlt className="text-blue-500 text-sm mt-1 flex-shrink-0" />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-gray-900 truncate">
                    {suggestion.structured_formatting?.main_text || suggestion.description}
                  </p>
                  {suggestion.structured_formatting?.secondary_text && (
                    <p className="text-xs text-gray-500 truncate">
                      {suggestion.structured_formatting.secondary_text}
                    </p>
                  )}
                </div>
              </div>
            </button>
          ))}
        </div>
        )}
    </div>
  );
};

