                  className="flex-1 bg-gray-600 text-white py-2 px-4 rounded-lg hover:bg-gray-700 transition-colors"
                >
                  View Mortgages
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

