import React, { useState, useEffect } from 'react';
import { FaTimes, FaCheckCircle, FaCreditCard, FaLock } from 'react-icons/fa';

const SimplePaymentModal = ({ 
  isOpen, 
  onClose, 
  amount = 50000, 
  propertyTitle,
  onPaymentSuccess,
  onPaymentError 
}) => {
  const [paymentStep, setPaymentStep] = useState('details');
  const [isProcessing, setIsProcessing] = useState(false);
  const [paymentComplete, setPaymentComplete] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState('card'); // 'card' or 'transfer'
  const [formData, setFormData] = useState({
    email: '',
    cardNumber: '',
    expiry: '',
    cvv: '',
    cardName: '',
    accountName: '',
    bankName: '',
    transferReference: ''
  });

  // Reset form when modal opens
  useEffect(() => {
    if (isOpen) {
      setPaymentStep('details');
      setIsProcessing(false);
      setPaymentComplete(false);
      setFormData({
        email: '',
        cardNumber: '',
        expiry: '',
        cvv: '',
        cardName: '',
        accountName: '',
        bankName: '',
        transferReference: ''
      });
      setPaymentMethod('card');
    }
  }, [isOpen]);

  const formatCardNumber = (value) => {
    const cleaned = value.replace(/\s/g, '');
    const chunks = cleaned.match(/.{1,4}/g) || [];
    return chunks.join(' ');
  };

  const formatExpiry = (value) => {
    const cleaned = value.replace(/\D/g, '');
    if (cleaned.length >= 2) {
      return cleaned.slice(0, 2) + '/' + cleaned.slice(2, 4);
    }
    return cleaned;
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;

    if (name === 'cardNumber') {
      setFormData(prev => ({
        ...prev,
        [name]: formatCardNumber(value)
      }));
    } else if (name === 'expiry') {
      setFormData(prev => ({
        ...prev,
        [name]: formatExpiry(value)
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Basic validation
    if (!formData.email) {
      alert('Please fill in your email address');
      return;
    }

    if (paymentMethod === 'card') {
      if (!formData.cardNumber || !formData.expiry || !formData.cvv) {
        alert('Please fill in all card details');
        return;
      }
    } else if (paymentMethod === 'transfer') {
      if (!formData.accountName || !formData.bankName || !formData.transferReference) {
        alert('Please fill in all transfer details');
        return;
      }
    }

    setIsProcessing(true);
    setPaymentStep('processing');

    // Simulate payment processing
    setTimeout(() => {
      setIsProcessing(false);
      setPaymentStep('success');
      setPaymentComplete(true);

      // Generate mock payment reference
      const paymentRef = paymentMethod === 'card' 
        ? 'CARD_' + Date.now()
        : 'TRANSFER_' + Date.now();

      // Call success callback
      if (onPaymentSuccess) {
        onPaymentSuccess({
          reference: paymentRef,
          amount: amount,
          method: paymentMethod,
          status: 'successful',
          timestamp: new Date().toISOString()
        });
      }
    }, paymentMethod === 'card' ? 2000 : 1500);
  };

  const handleClose = () => {
    if (paymentComplete) {
      onClose();
    } else {
      if (window.confirm('Are you sure you want to cancel this payment?')) {
        onClose();
      }
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto">
      <div className="flex min-h-screen items-center justify-center p-4">
        <div className="fixed inset-0 bg-black bg-opacity-50" onClick={handleClose}></div>

        <div className="relative bg-white rounded-lg shadow-xl max-w-md w-full max-h-[90vh] overflow-y-auto">
          {/* Header */}
          <div className="bg-gradient-to-r from-blue-600 to-blue-700 text-white p-6 rounded-t-lg">
            <div className="flex justify-between items-start">
