import React, { useState, useRef, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useGlobalSearch } from '../hooks/useGlobalSearch';
import GlobalSearch from './GlobalSearch';
import { FaSearch, FaArrowRight } from 'react-icons/fa';

const StaticHeroBanner = ({ onOpenRegisterModal }) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const { isSearchOpen, openSearch, closeSearch, handleResultClick } = useGlobalSearch();
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuggestions, setShowSuggestions] = useState(false);
  const inputRef = useRef(null);
  const searchContainerRef = useRef(null);

  // Beautiful real estate image - Replace with your own image featuring Nigerians in real estate context
  // Recommended: Use a high-quality image (1920x600px or larger) showing modern Nigerian real estate with people
  // You can upload your image to a CDN or use your own image hosting service
  const backgroundImage = "https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=1920&q=80&auto=format&fit=crop";

  // Popular search suggestions
  const popularSearches = [
    'Lekki Phase 1',
    'Victoria Island',
    'Ikoyi',
    'Banana Island',
    '3 Bedroom Apartment',
    'Luxury Villa',
    'For Sale',
    'For Rent'
  ];

  // Handle search submission
  const handleSearch = (query = searchQuery) => {
    const trimmedQuery = (query || searchQuery).trim();

    if (!trimmedQuery) {
      // If empty, open advanced search modal
      openSearch();
      return;
    }

    // Navigate to properties page with search query
    const searchParams = new URLSearchParams();
    searchParams.set('search', trimmedQuery);

    // Check if query looks like a location (contains common location keywords)
    const locationKeywords = ['lagos', 'abuja', 'lekki', 'ikoyi', 'victoria', 'banana', 'island', 'phase', 'gra', 'maitama', 'wuse', 'surulere', 'yaba'];
    const isLocation = locationKeywords.some(keyword => trimmedQuery.toLowerCase().includes(keyword));

    if (isLocation) {
      searchParams.set('location', trimmedQuery);
    }

    navigate(`/properties?${searchParams.toString()}`);
    setShowSuggestions(false);
  };

  // Handle Enter key press
  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleSearch();
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  // Handle input focus
  const handleInputFocus = () => {
    if (searchQuery.trim()) {
      setShowSuggestions(true);
    }
  };

  // Handle input change
  const handleInputChange = (e) => {
    const value = e.target.value;
    setSearchQuery(value);
    setShowSuggestions(value.trim().length > 0);
  };

  // Handle suggestion click
  const handleSuggestionClick = (suggestion) => {
    setSearchQuery(suggestion);
    handleSearch(suggestion);
  };

  // Close suggestions when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchContainerRef.current && !searchContainerRef.current.contains(event.target)) {
        setShowSuggestions(false);
      }
    };

    if (showSuggestions) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [showSuggestions]);

  // Filter popular searches based on input
  const filteredSuggestions = searchQuery.trim()
    ? popularSearches.filter(suggestion => 
        suggestion.toLowerCase().includes(searchQuery.toLowerCase())
      ).slice(0, 5)
    : popularSearches.slice(0, 5);

  return (
    <div className="relative h-[420px] sm:h-[520px] md:h-[600px] w-full overflow-hidden shadow-2xl">
      {/* Background Image */}
      <div 
        className="absolute inset-0 bg-cover bg-center"
        style={{
          backgroundImage: `url(${backgroundImage})`,
        }}
      >
        {/* Dark overlay for text readability */}
        <div className="absolute inset-0 bg-gradient-to-b from-black/60 via-black/50 to-black/70"></div>
      </div>

      {/* Content */}
      <div className="relative z-10 h-full flex flex-col items-center justify-center px-4 sm:px-6 lg:px-8">
        <div className="w-full max-w-6xl">
          {/* Main Heading */}
          <div className="text-center mb-8">
            <h1 className="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-bold text-white mb-4 leading-tight">
              Find Your Dream Property <span className="text-orange-400">in Nigeria</span>
            </h1>
            <p className="text-lg sm:text-xl text-white/90 mt-2">
              Search thousands of properties for sale, rent, and investment opportunities
            </p>
          </div>

          {/* Search Bar - Prominent in Banner */}
          <div className="w-full max-w-4xl mx-auto mb-6" ref={searchContainerRef}>
            <div className="bg-white rounded-2xl shadow-2xl p-2 relative">
              <div className="relative flex-1">
                <FaSearch className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400 text-xl z-10" />
                <input
                  ref={inputRef}
                  type="text"
                  placeholder="Search properties, locations, investments..."
                  value={searchQuery}
                  onChange={handleInputChange}
                  onFocus={handleInputFocus}
                  onKeyDown={handleKeyPress}
                  className="w-full pl-12 pr-4 py-4 text-lg border-0 rounded-xl focus:ring-2 focus:ring-orange-500 focus:outline-none"
                />

                {/* Search Suggestions Dropdown */}
                {showSuggestions && filteredSuggestions.length > 0 && (
                  <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-xl shadow-2xl border border-gray-200 z-50 max-h-64 overflow-y-auto">
                    {filteredSuggestions.map((suggestion, index) => (
                      <button
                        key={index}
                        onClick={() => handleSuggestionClick(suggestion)}
                        className="w-full px-4 py-3 text-left hover:bg-orange-50 transition-colors flex items-center space-x-2 text-gray-700"
                      >
                        <FaSearch className="text-gray-400 text-sm" />
                        <span>{suggestion}</span>
                      </button>
                    ))}
                    <div className="border-t border-gray-200 px-4 py-2">
                      <button
                        onClick={openSearch}
                        className="text-sm text-orange-500 hover:text-orange-600 font-medium w-full text-left"
                      >
                        Advanced Search →
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* CTA Buttons */}
          <div className="flex items-center justify-center space-x-3 mt-4">
              <button
                onClick={(e) => {
                  e.preventDefault();
                  if (typeof onOpenRegisterModal === 'function') {
                    onOpenRegisterModal();
                  }
                }}
                className="inline-block px-6 py-4 bg-brand-orange text-white rounded-2xl hover:bg-orange-600 text-lg font-semibold shadow-lg"
              >
                Get started
              </button>
            <button onClick={() => { navigate('/properties'); window.scrollTo({ top: 0, behavior: 'instant' }); }} className="inline-flex items-center space-x-2 px-5 py-3 bg-white/10 text-white rounded-2xl border border-white/20 hover:bg-white/20">
              <span>Explore listings</span>
              <FaArrowRight />
            </button>
          </div>
        </div>
      </div>

      {/* Global Search Modal */}
      <GlobalSearch 
        isOpen={isSearchOpen} 
        onClose={closeSearch} 
        onResultClick={handleResultClick}
      />
    </div>
  );
};

export default StaticHeroBanner;

import React, { useState, useEffect, useMemo } from 'react';
import { FaCreditCard, FaCalendarAlt, FaExclamationTriangle, FaCheckCircle, FaTimesCircle, FaClock, FaShieldAlt, FaStar, FaChartLine, FaUsers, FaHome } from 'react-icons/fa';
import { getApiUrl } from '../utils/apiConfig';
import { useAuth } from '../contexts/AuthContext';
import { authenticatedFetch } from '../utils/authToken';
import SubscriptionPaymentModal from './SubscriptionPaymentModal';

const SubscriptionDashboard = () => {
  const { user } = useAuth();
  const [subscription, setSubscription] = useState(null);
  const [subscriptionStatus, setSubscriptionStatus] = useState(null);
  const [plans, setPlans] = useState([]);
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState(null);
  const [countdown, setCountdown] = useState(null);

  useEffect(() => {
    fetchSubscriptionData();
  }, []);

  const countdownTarget = useMemo(() => {
    if (!subscriptionStatus && !subscription) return null;

    const labelFor = (type) => {
      if (type === 'trial') return 'Trial ends in';
      return 'Next billing in';
    };

    if (subscription?.trialEndDate && subscriptionStatus?.status === 'trial') {
      return {
        label: labelFor('trial'),
        date: new Date(subscription.trialEndDate)
      };
    }

    const nextDateString = subscription?.nextPaymentDate || subscriptionStatus?.nextPaymentDate;
    if (nextDateString) {
      return {
        label: labelFor('billing'),
        date: new Date(nextDateString)
      };
    }

    return null;
  }, [subscriptionStatus, subscription]);

  useEffect(() => {
    if (!countdownTarget?.date) {
      setCountdown(null);
      return;
    }

    const updateCountdown = () => {
      const now = new Date();
      const diff = countdownTarget.date.getTime() - now.getTime();

      if (diff <= 0) {
        setCountdown({ label: countdownTarget.label, expired: true, display: 'Due now' });
        return;
      }

      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
      const hours = Math.floor((diff / (1000 * 60 * 60)) % 24);
      const minutes = Math.floor((diff / (1000 * 60)) % 60);
      const seconds = Math.floor((diff / 1000) % 60);

      const pad = (value) => String(value).padStart(2, '0');
      const display = `${days}d ${pad(hours)}h:${pad(minutes)}m:${pad(seconds)}s`;

      setCountdown({
        label: countdownTarget.label,
        display,
        nextDate: countdownTarget.date
      });
    };

    updateCountdown();
    const timer = setInterval(updateCountdown, 1000);

    return () => clearInterval(timer);
  }, [countdownTarget]);

  const currentPlanDetails = useMemo(() => {
    if (!plans?.length || !subscription) return null;
    return plans.find((plan) => plan.id === subscription.planId || plan.name === subscription.plan) || null;
  }, [plans, subscription]);

  const fetchSubscriptionData = async () => {
    try {
      setLoading(true);

      // Fetch subscription status
      const statusResponse = await authenticatedFetch(getApiUrl('/subscription/status'));
      if (statusResponse.ok) {
        const statusData = await statusResponse.json();
        setSubscriptionStatus(statusData.data);
      }

      // Fetch current subscription
      const subResponse = await authenticatedFetch(getApiUrl('/subscription/current'));
      if (subResponse.ok) {
        const subData = await subResponse.json();
        setSubscription(subData.data);
      }

      // Fetch available plans
      const plansResponse = await fetch(getApiUrl('/subscription/plans'));
      if (plansResponse.ok) {
        const plansData = await plansResponse.json();
        setPlans(plansData.data);
      }

      // Fetch payment history
      const paymentsResponse = await authenticatedFetch(getApiUrl('/subscription/payments'));
      if (paymentsResponse.ok) {
        const paymentsData = await paymentsResponse.json();
        setPayments(paymentsData.data);
      }
    } catch (error) {
      console.error('Error fetching subscription data:', error);
      setError('Failed to load subscription data');
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'trial':
        return <FaClock className="text-yellow-500" />;
      case 'active':
        return <FaCheckCircle className="text-green-500" />;
      case 'expired':
        return <FaExclamationTriangle className="text-red-500" />;
      case 'suspended':
        return <FaTimesCircle className="text-gray-600" />;
      case 'cancelled':
        return <FaTimesCircle className="text-gray-500" />;
      default:
        return <FaExclamationTriangle className="text-gray-400" />;
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'trial':
        return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'active':
        return 'bg-green-100 text-green-800 border-green-200';
      case 'expired':
        return 'bg-red-100 text-red-800 border-red-200';
      case 'suspended':
        return 'bg-gray-100 text-gray-800 border-gray-200';
      case 'cancelled':
        return 'bg-gray-100 text-gray-600 border-gray-200';
      default:
        return 'bg-gray-100 text-gray-600 border-gray-200';
    }
  };

  const formatCurrency = (amount, currency = 'NGN') => {
    return new Intl.NumberFormat('en-NG', {
      style: 'currency',
      currency: currency,
      minimumFractionDigits: 0
    }).format(amount);
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-NG', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  const defaultPlan = useMemo(() => ({
    id: 'vendor-default-plan',
    name: 'Vendor Subscription',
    amount: subscription?.amount || subscriptionStatus?.suggestedAmount || 50000,
    billingCycle: subscription?.billingCycle || subscription?.interval || 'monthly',
    features: {
      property_listings: true,
      escrow_support: true,
      analytics: true,
      premium_support: false
    }
  }), [subscription, subscriptionStatus]);

  const handlePayment = (plan) => {
    setSelectedPlan(plan);
    setShowPaymentModal(true);
  };

  const resolveDefaultPlan = () => {
    if (plans && plans.length > 0) return plans[0];
    if (currentPlanDetails) return currentPlanDetails;
    return defaultPlan;
  };

  const handleRenewCurrentPlan = () => {
    const planToUse = currentPlanDetails || resolveDefaultPlan();
    if (!planToUse) {
      setError('No subscription plan available yet. Please contact support.');
      return;
    }
    handlePayment(planToUse);
  };

  const handleSubscribeNow = () => {
    const planToUse = resolveDefaultPlan();
    if (!planToUse) {
      setError('No subscription plan available yet. Please contact support.');
      return;
    }
    handlePayment(planToUse);
  };

  const handlePaymentSuccess = (paymentData) => {
    // Refresh subscription data
    fetchSubscriptionData();
    setError('');
  };

  const handleCancelSubscription = async () => {
    if (!window.confirm('Are you sure you want to cancel your subscription?')) {
      return;
    }

    try {
      const response = await authenticatedFetch(getApiUrl('/subscription/cancel'), {
        method: 'POST'
      });

      const result = await response.json();

      if (result.success) {
        fetchSubscriptionData();
      } else {
        setError(result.message || 'Failed to cancel subscription');
      }
    } catch (error) {
      console.error('Cancel error:', error);
      setError('Failed to cancel subscription');
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-white rounded-lg shadow-sm p-6">
        <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
          <div>
            <h2 className="text-2xl font-bold text-gray-900 mb-2">Subscription Management</h2>
            <p className="text-gray-600">Manage your vendor subscription and billing</p>
          </div>
          <button
            onClick={handleSubscribeNow}
            disabled={loading}
            className={`inline-flex items-center justify-center px-4 py-2 rounded-lg text-white transition-colors ${loading ? 'bg-blue-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'}`}
          >
            <FaCreditCard className="mr-2" />
            Subscribe Now
          </button>
        </div>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <div className="flex items-center">
            <FaExclamationTriangle className="text-red-500 mr-2" />
            <span className="text-red-700">{error}</span>
          </div>
        </div>
      )}

      {/* Subscription Status Card */}
      {subscriptionStatus && (
        <div className="bg-white rounded-lg shadow-sm p-6">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-gray-900">Current Status</h3>
            <div className={`flex items-center px-3 py-1 rounded-full border ${getStatusColor(subscriptionStatus.status)}`}>
              {getStatusIcon(subscriptionStatus.status)}
              <span className="ml-2 text-sm font-medium capitalize">{subscriptionStatus.status}</span>
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <span className="text-gray-600">Status Message:</span>
              <span className="font-medium">{subscriptionStatus.message}</span>
            </div>

            {subscriptionStatus.trialDaysRemaining > 0 && (
              <div className="flex items-center justify-between">
                <span className="text-gray-600">Trial Days Remaining:</span>
                <span className="font-medium">{subscriptionStatus.trialDaysRemaining} days</span>
              </div>
            )}

            {subscription && (
              <>
                <div className="flex items-center justify-between">
                  <span className="text-gray-600">Plan:</span>
                  <span className="font-medium">{subscription.plan}</span>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-gray-600">Amount:</span>
                  <span className="font-medium">{formatCurrency(subscription.amount)}</span>
                </div>
                {subscription.trialEndDate && (
                  <div className="flex items-center justify-between">
                    <span className="text-gray-600">Trial Ends:</span>
                    <span className="font-medium">{formatDate(subscription.trialEndDate)}</span>
                  </div>
                )}
                {subscription.nextPaymentDate && (
                  <div className="flex items-center justify-between">
                    <span className="text-gray-600">Next Payment:</span>
                    <span className="font-medium">{formatDate(subscription.nextPaymentDate)}</span>
                  </div>
                )}
              </>
            )}
          </div>

          {/* Action Buttons */}
          <div className="mt-6 flex space-x-4">
            {subscription && subscription.status === 'active' && (
              <button
                onClick={handleCancelSubscription}
                className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition-colors"
              >
                <FaTimesCircle className="inline mr-2" />
                Cancel Subscription
              </button>
            )}
          </div>
        </div>
      )}

      {/* Countdown / Renewal Card */}
      {countdown && (
        <div className="bg-white rounded-lg shadow-sm p-6 border border-blue-100">
          <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-6">
            <div>
              <p className="text-sm uppercase tracking-wide text-blue-500 font-semibold">{countdown.label}</p>
              <p className="text-3xl font-bold text-gray-900 mt-1">{countdown.display}</p>
              {countdown.nextDate && (
                <p className="text-sm text-gray-500 mt-1">
                  Next cycle date: <span className="font-medium">{formatDate(countdown.nextDate)}</span>
                </p>
              )}
            </div>
            <div className="flex flex-col items-start md:items-end gap-2">
              <p className="text-sm text-gray-600">
                Keep your listings live by renewing before the timer hits zero.
              </p>
              <button
                onClick={handleRenewCurrentPlan}
                className="inline-flex items-center bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
              >
                <FaCreditCard className="mr-2" />
                {subscriptionStatus?.status === 'trial' ? 'Activate plan' : 'Renew subscription'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Available Plans */}
      {plans.length > 0 ? (
        <div className="bg-white rounded-lg shadow-sm p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Available Plans</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {plans.map((plan) => (
              <div key={plan.id} className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow">
                <div className="mb-4">
                  <h4 className="font-semibold text-gray-900">{plan.name}</h4>
                  <p className="text-2xl font-bold text-blue-600 mt-2">
                    {formatCurrency(plan.amount)}
                    <span className="text-sm text-gray-500 font-normal">/{plan.billingCycle}</span>
                  </p>
                </div>

                <div className="space-y-2 mb-4">
                  {plan.features && Object.entries(plan.features).map(([key, value]) => (
                    <div key={key} className="flex items-center text-sm">
                      {value ? (
                        <FaCheckCircle className="text-green-500 mr-2" />
                      ) : (
                        <FaTimesCircle className="text-gray-400 mr-2" />
                      )}
                      <span className="text-gray-700 capitalize">
                        {key.replace(/_/g, ' ')}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="bg-white rounded-lg shadow-sm p-6">
          <div className="flex items-center justify-between mb-4">
            <div>
