import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { FaCalendar, FaClock, FaMapMarkerAlt, FaUser, FaPhone, FaEnvelope, FaCheckCircle, FaTimesCircle, FaCalendarAlt, FaEye } from 'react-icons/fa';
import { listInspectionRequestsByVendor, updateInspectionRequest, getInspectionAnalytics } from '../services/inspectionService';
import toast from 'react-hot-toast';

const VendorInspectionRequests = () => {
  const { user } = useAuth();
  const [requests, setRequests] = useState([]);
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState(null);
  const [responseType, setResponseType] = useState('accept');
  const [proposedDate, setProposedDate] = useState('');
  const [proposedTime, setProposedTime] = useState('');
  const [vendorMessage, setVendorMessage] = useState('');

  useEffect(() => {
    loadInspectionRequests();
  }, [user]);

  useEffect(() => {
    if (!user?.id && !user?.email) {
      setAnalytics(null);
      return;
    }
    setAnalytics(getInspectionAnalytics({ role: 'vendor', vendorId: user?.id, vendorEmail: user?.email }));

    const handleAnalyticsUpdate = (event) => {
      const detail = event.detail || event;
      if (detail?.vendorId && detail.vendorId !== user?.id) return;
      setAnalytics(getInspectionAnalytics({ role: 'vendor', vendorId: user?.id, vendorEmail: user?.email }));
    };

    window.addEventListener('inspectionAnalyticsUpdated', handleAnalyticsUpdate);
    return () => window.removeEventListener('inspectionAnalyticsUpdated', handleAnalyticsUpdate);
  }, [user?.id, user?.email]);

  const loadInspectionRequests = async () => {
    try {
      setLoading(true);
      const data = await listInspectionRequestsByVendor(user?.id, user?.email);
      setRequests(data);
      if (user?.id || user?.email) {
        setAnalytics(getInspectionAnalytics({ role: 'vendor', vendorId: user?.id, vendorEmail: user?.email }));
      }
    } catch (error) {
      console.error('Error loading inspection requests:', error);
      toast.error('Failed to load inspection requests');
    } finally {
      setLoading(false);
    }
  };

  const handleRespondToRequest = (request, initialType = 'accept') => {
    setSelectedRequest(request);
    setShowResponseModal(true);
    setProposedDate(request.preferredDate);
    setProposedTime(request.preferredTime);
    setVendorMessage('');
    setResponseType(initialType);
  };

  const handleSubmitResponse = async () => {
    if (!selectedRequest) return;

    try {
      let updates = {};
      
      if (responseType === 'accept') {
        updates = {
          status: 'accepted',
          confirmedDate: selectedRequest.preferredDate,
          confirmedTime: selectedRequest.preferredTime,
          vendorMessage: vendorMessage || 'Viewing confirmed. Looking forward to showing you the property!'
        };
      } else if (responseType === 'propose') {
        if (!proposedDate || !proposedTime) {
          toast.error('Please select a proposed date and time');
          return;
        }
        updates = {
          status: 'proposed_new_time',
          proposedDate,
          proposedTime,
          vendorMessage: vendorMessage || 'I would like to propose a different time. Please let me know if this works for you.'
        };
      } else if (responseType === 'decline') {
        updates = {
          status: 'declined',
          vendorMessage: vendorMessage || 'Unfortunately, I am not available at the requested time.'
        };
      }

      const success = await updateInspectionRequest(selectedRequest.id, updates);
      
      if (success) {
        toast.success(`Request ${responseType === 'accept' ? 'accepted' : responseType === 'propose' ? 'updated with new time' : 'declined'}`);
        setShowResponseModal(false);
        setSelectedRequest(null);
        loadInspectionRequests(); // Reload requests
      } else {
        toast.error('Failed to update request');
      }
    } catch (error) {
      console.error('Error updating request:', error);
      toast.error('Failed to update request');
    }
  };

  const getStatusBadge = (status) => {
    const badges = {
      'pending_vendor': { color: 'bg-yellow-100 text-yellow-800', text: 'Pending Response' },
      'accepted': { color: 'bg-green-100 text-green-800', text: 'Accepted' },
      'proposed_new_time': { color: 'bg-blue-100 text-blue-800', text: 'New Time Proposed' },
      'declined': { color: 'bg-red-100 text-red-800', text: 'Declined' },
      'buyer_rescheduled': { color: 'bg-purple-100 text-purple-800', text: 'Buyer Rescheduled' },
      'cancelled_by_buyer': { color: 'bg-gray-200 text-gray-700', text: 'Cancelled by Buyer' },
      'cancelled_by_vendor': { color: 'bg-gray-200 text-gray-700', text: 'Cancelled by You' }
    };
    
    const badge = badges[status] || badges['pending_vendor'];
    return (
      <span className={`px-2 py-1 rounded-full text-xs font-medium ${badge.color}`}>
        {badge.text}
      </span>
    );
  };

  const formatDateTime = (date, time) => {
    if (!date || !time) return 'Not specified';
    try {
      const dateObj = new Date(`${date}T${time}`);
      return dateObj.toLocaleDateString() + ' at ' + dateObj.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return `${date} at ${time}`;
    }
  };

  const handleAcceptBuyerReschedule = async (request) => {
    const ok = await updateInspectionRequest(request.id, {
      status: 'accepted',
      confirmedDate: request.preferredDate,
      confirmedTime: request.preferredTime,
      vendorMessage: 'Buyer reschedule accepted'
    });
    if (ok) {
      toast.success('Rescheduled inspection confirmed');
      loadInspectionRequests();
    } else {
      toast.error('Failed to confirm reschedule');
    }
  };

  const handleVendorCancel = async (request) => {
    const confirmCancel = window.confirm('Cancel this inspection? The buyer will be notified.');
    if (!confirmCancel) return;
    const ok = await updateInspectionRequest(request.id, {
      status: 'cancelled_by_vendor',
      vendorMessage: 'Vendor cancelled the appointment',
      cancelledAt: new Date().toISOString()
    });
    if (ok) {
      toast.success('Inspection cancelled');
      loadInspectionRequests();
    } else {
      toast.error('Failed to cancel inspection');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
        <span className="ml-2">Loading inspection requests...</span>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-900">Property Viewing Requests</h2>
        <button
          onClick={loadInspectionRequests}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
        >
          Refresh
        </button>
      </div>

      {analytics && (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-blue-50 border border-blue-100 rounded-xl p-4">
            <p className="text-sm text-blue-600">Pending Responses</p>
            <p className="text-3xl font-semibold text-blue-900">{analytics.pendingResponses}</p>
          </div>
          <div className="bg-green-50 border border-green-100 rounded-xl p-4">
            <p className="text-sm text-green-600">Confirmed</p>
            <p className="text-3xl font-semibold text-green-900">{analytics.confirmed}</p>
          </div>
          <div className="bg-purple-50 border border-purple-100 rounded-xl p-4">
            <p className="text-sm text-purple-600">Buyer Reschedules</p>
            <p className="text-3xl font-semibold text-purple-900">{analytics.buyerReschedules}</p>
          </div>
          <div className="bg-red-50 border border-red-100 rounded-xl p-4">
            <p className="text-sm text-red-600">Buyer Cancellations</p>
            <p className="text-3xl font-semibold text-red-900">{analytics.cancelledByBuyer}</p>
          </div>
        </div>
      )}

      {requests.length === 0 ? (
        <div className="text-center py-12">
          <FaCalendar className="mx-auto text-4xl text-gray-400 mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No viewing requests yet</h3>
          <p className="text-gray-500">When buyers request to view your properties, they will appear here.</p>
        </div>
      ) : (
        <div className="grid gap-6">
          {requests.map((request) => (
            <div key={request.id} className="bg-white rounded-lg border border-gray-200 p-6 hover:shadow-md transition-shadow">
              <div className="flex items-start justify-between mb-4">
                <div className="flex-1">
                  <h3 className="text-lg font-semibold text-gray-900 mb-2">
                    {request.propertyTitle || request.projectName}
                  </h3>
                  <div className="flex items-center text-sm text-gray-600 mb-2">
                    <FaMapMarkerAlt className="mr-2" />
                    {request.propertyLocation || request.projectLocation}
                  </div>
                  <div className="flex items-center text-sm text-gray-600">
                    <FaUser className="mr-2" />
                    {request.buyerName || request.userName}
                  </div>
                </div>
                <div className="ml-4">
                  {getStatusBadge(request.status)}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                <div className="flex items-center text-sm text-gray-600">
                  <FaCalendar className="mr-2" />
                  <span>Requested: {formatDateTime(request.preferredDate, request.preferredTime)}</span>
                </div>
                {request.confirmedDate && request.confirmedTime && (
                  <div className="flex items-center text-sm text-green-600">
                    <FaCheckCircle className="mr-2" />
                    <span>Confirmed: {formatDateTime(request.confirmedDate, request.confirmedTime)}</span>
                  </div>
                )}
                {request.proposedDate && request.proposedTime && request.status === 'proposed_new_time' && (
                  <div className="flex items-center text-sm text-blue-600">
                    <FaCalendarAlt className="mr-2" />
                    <span>Proposed: {formatDateTime(request.proposedDate, request.proposedTime)}</span>
                  </div>
                )}
              </div>

              {request.message && (
                <div className="mb-4 p-3 bg-gray-50 rounded-lg">
                  <p className="text-sm text-gray-700">
                    <strong>Buyer's message:</strong> {request.message}
                  </p>
                </div>
              )}

              {request.vendorMessage && (
                <div className="mb-4 p-3 bg-blue-50 rounded-lg">
                  <p className="text-sm text-gray-700">
                    <strong>Your response:</strong> {request.vendorMessage}
                  </p>
                </div>
              )}

              {request.buyerMessage && (
                <div className="mb-4 p-3 bg-purple-50 rounded-lg">
                  <p className="text-sm text-gray-700">
                    <strong>Buyer update:</strong> {request.buyerMessage}
                  </p>
                </div>
              )}

              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-4 text-sm text-gray-600">
                  <span className="flex items-center">
                    <FaPhone className="mr-1" />
                    {request.buyerPhone || 'Not provided'}
                  </span>
                  <span className="flex items-center">
                    <FaEnvelope className="mr-1" />
                    {request.buyerEmail || request.userEmail}
                  </span>
                </div>

                {request.status === 'pending_vendor' && (
                  <button
                    onClick={() => handleRespondToRequest(request)}
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                  >
                    Respond
                  </button>
                )}

                {request.status === 'buyer_rescheduled' && (
                  <div className="flex flex-wrap gap-3">
                    <button
                      onClick={() => handleAcceptBuyerReschedule(request)}
                      className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
                    >
                      Accept New Time
                    </button>
                    <button
                      onClick={() => handleRespondToRequest(request, 'propose')}
                      className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                    >
                      Propose Another Time
                    </button>
                  </div>
                )}

                {request.status === 'accepted' && (
                  <div className="flex flex-wrap gap-3">
                    <button
                      onClick={() => handleRespondToRequest(request, 'propose')}
                      className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                    >
                      Reschedule
                    </button>
                    <button
                      onClick={() => handleVendorCancel(request)}
                      className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors"
                    >
                      Cancel
                    </button>
                  </div>
                )}

                {request.status === 'cancelled_by_buyer' && (
                  <span className="text-sm text-gray-500">Buyer cancelled this appointment</span>
                )}

                {request.status === 'cancelled_by_vendor' && (
                  <span className="text-sm text-gray-500">You cancelled this appointment</span>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Response Modal */}
      {showResponseModal && selectedRequest && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-lg max-w-md w-full p-6">
            <h3 className="text-lg font-semibold mb-4">Respond to Viewing Request</h3>
            
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Response Type</label>
                <div className="space-y-2">
                  <label className="flex items-center">
                    <input
                      type="radio"
                      value="accept"
                      checked={responseType === 'accept'}
                      onChange={(e) => setResponseType(e.target.value)}
                      className="mr-2"
                    />
                    Accept as requested
                  </label>
                  <label className="flex items-center">
                    <input
                      type="radio"
                      value="propose"
                      checked={responseType === 'propose'}
                      onChange={(e) => setResponseType(e.target.value)}
                      className="mr-2"
                    />
                    Propose different time
                  </label>
                  <label className="flex items-center">
                    <input
                      type="radio"
                      value="decline"
                      checked={responseType === 'decline'}
                      onChange={(e) => setResponseType(e.target.value)}
                      className="mr-2"
                    />
                    Decline request
                  </label>
                </div>
              </div>

              {responseType === 'propose' && (
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Proposed Date</label>
                    <input
                      type="date"
                      value={proposedDate}
                      onChange={(e) => setProposedDate(e.target.value)}
                      className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Proposed Time</label>
                    <input
                      type="time"
                      value={proposedTime}
                      onChange={(e) => setProposedTime(e.target.value)}
                      className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    />
                  </div>
                </div>
              )}

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Message (Optional)</label>
                <textarea
                  value={vendorMessage}
                  onChange={(e) => setVendorMessage(e.target.value)}
                  rows={3}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="Add a personal message..."
                />
              </div>
            </div>

            <div className="flex justify-end space-x-3 mt-6">
              <button
                onClick={() => setShowResponseModal(false)}
                className="px-4 py-2 text-gray-700 border border-gray-300 rounded-md hover:bg-gray-50"
              >
                Cancel
              </button>
              <button
                onClick={handleSubmitResponse}
                className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700"
              >
                Submit Response
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default VendorInspectionRequests;

import React, { useState, useEffect } from 'react';
import { FaExclamationTriangle, FaShieldAlt, FaCreditCard, FaClock, FaCheckCircle, FaTimes } from 'react-icons/fa';
import { getApiUrl } from '../utils/apiConfig';
import { useAuth } from '../contexts/AuthContext';
import { authenticatedFetch } from '../utils/authToken';

const VendorOnboardingWarning = ({ onboardingStep = 'complete', onDismiss }) => {
  const { user } = useAuth();
  const [subscriptionStatus, setSubscriptionStatus] = useState(null);
  const [dismissed, setDismissed] = useState(false);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (user?.roles?.includes('vendor') || user?.role === 'vendor') {
      fetchSubscriptionStatus();
    }
  }, [user]);

  const fetchSubscriptionStatus = async () => {
    try {
      const response = await authenticatedFetch(getApiUrl('/subscription/status'));
      if (response.ok) {
        const data = await response.json();
        setSubscriptionStatus(data.data);
      }
    } catch (error) {
      console.error('Error fetching subscription status:', error);
    }
  };

  const handleDismiss = async () => {
    setDismissed(true);
    onDismiss && onDismiss();
  };

  const handlePaymentSetup = () => {
    window.location.href = '/dashboard?tab=subscription';
  };

  if (dismissed) return null;

  // Show different warnings based on onboarding step and subscription status
  const getWarningContent = () => {
    if (onboardingStep === 'registration') {
      return {
        type: 'info',
        title: 'Vendor Registration - Important Information',
        icon: <FaShieldAlt className="text-blue-500" />,
        color: 'bg-blue-50 border-blue-200 text-blue-800',
        points: [
          '• 3-month free trial period for all new vendors',
          '• After trial: N50,000/month subscription fee',
          '• Payment via Paystack (card, bank transfer, etc.)',
          '• <strong>Warning: Falsified details = Immediate suspension</strong>',
          '• Auto-approval but subject to verification'
        ],
        action: null
      };
    }

    if (onboardingStep === 'complete' && subscriptionStatus) {
      if (subscriptionStatus.status === 'trial' && subscriptionStatus.trialDaysRemaining > 60) {
        return {
          type: 'info',
          title: 'Subscription Trial Active',
          icon: <FaClock className="text-yellow-500" />,
          color: 'bg-yellow-50 border-yellow-200 text-yellow-800',
          points: [
            `• ${subscriptionStatus.trialDaysRemaining} days remaining in free trial`,
            '• After trial: N50,000/month subscription fee',
            '• Set up payment method to avoid interruption',
            '• <strong>Falsified details = Immediate suspension</strong>'
          ],
          action: {
            text: 'Set Up Payment Method',
            handler: handlePaymentSetup
          }
        };
      }

      if (subscriptionStatus.status === 'trial' && subscriptionStatus.trialDaysRemaining <= 7) {
        return {
          type: 'warning',
          title: 'Trial Ending Soon - Action Required',
          icon: <FaExclamationTriangle className="text-orange-500" />,
          color: 'bg-orange-50 border-orange-200 text-orange-800',
          points: [
            `• Only ${subscriptionStatus.trialDaysRemaining} days left in trial`,
            '• Account will be suspended if payment not set up',
            '• Subscribe now to continue using platform',
            '• <strong>Immediate suspension for falsified details</strong>'
          ],
          action: {
            text: 'Subscribe Now',
            handler: handlePaymentSetup
          }
        };
      }

      if (subscriptionStatus.status === 'expired') {
        return {
          type: 'error',
          title: 'Trial Expired - Account Suspended',
          icon: <FaExclamationTriangle className="text-red-500" />,
          color: 'bg-red-50 border-red-200 text-red-800',
          points: [
            '• Your free trial has expired',
            '• Account is currently suspended',
            '• Subscribe immediately to reactivate',
            '• <strong>Verify all details are accurate</strong>'
          ],
          action: {
            text: 'Subscribe Now',
            handler: handlePaymentSetup
          }
        };
      }

      if (subscriptionStatus.status === 'active') {
        return {
          type: 'success',
          title: 'Subscription Active',
          icon: <FaCheckCircle className="text-green-500" />,
          color: 'bg-green-50 border-green-200 text-green-800',
          points: [
            '• Your subscription is active and in good standing',
            '• Next payment date: ' + (subscriptionStatus.subscription?.nextPaymentDate ? 
              new Date(subscriptionStatus.subscription.nextPaymentDate).toLocaleDateString() : 'N/A'),
            '• Keep your details updated to avoid suspension',
            '• <strong>Report any issues to support</strong>'
          ],
          action: null
        };
      }
    }

    return null;
  };

  const warning = getWarningContent();

  if (!warning) return null;

  return (
    <div className={`rounded-lg border p-6 ${warning.color} relative`}>
      {/* Dismiss button */}
      <button
        onClick={handleDismiss}
        className="absolute top-4 right-4 text-current opacity-60 hover:opacity-100 transition-opacity"
      >
        <FaTimes />
      </button>

      {/* Warning Content */}
      <div className="flex items-start">
        <div className="flex-shrink-0 mr-3 mt-1">
          {warning.icon}
        </div>

        <div className="flex-1">
          <h3 className="font-semibold text-lg mb-3">{warning.title}</h3>

          <div className="space-y-2 mb-4">
            {warning.points.map((point, index) => (
              <p 
                key={index} 
                className="text-sm"
                dangerouslySetInnerHTML={{ __html: point }}
              />
            ))}
          </div>

          {/* Action Button */}
          {warning.action && (
            <button
              onClick={warning.action.handler}
              className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                warning.type === 'error' 
                  ? 'bg-red-600 text-white hover:bg-red-700'
                  : warning.type === 'warning'
                  ? 'bg-orange-600 text-white hover:bg-orange-700'
                  : 'bg-blue-600 text-white hover:bg-blue-700'
              }`}
            >
              {warning.action.text}
            </button>
          )}

          {/* Additional Info for Trial Users */}
          {subscriptionStatus?.status === 'trial' && (
            <div className="mt-4 pt-4 border-t border-current border-opacity-20">
              <div className="flex items-center text-sm">
                <FaCreditCard className="mr-2" />
                <span>Payment Methods: Card, Bank Transfer, USSD, QR Code</span>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default VendorOnboardingWarning;

import React, { useEffect, useState, useRef } from 'react';
import { FaTimes, FaVolumeUp, FaMicrophone, FaChevronRight, FaChevronLeft } from 'react-icons/fa';
import { useTour } from '../contexts/TourContext';

const VoiceTourGuide = () => {
  const {
    isTourActive,
    currentTourStep,
    tourSteps,
    tourProgress,
    getCurrentStep,
    nextStep,
    previousStep,
    completeTour,
    skipTour
  } = useTour();

  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceCommands, setVoiceCommands] = useState([]);
  const recognitionRef = useRef(null);
  const speakingRef = useRef(false);

  const currentStep = getCurrentStep();

  // Voice commands for tour navigation
  useEffect(() => {
    setVoiceCommands([
      { command: 'next', action: () => handleNext() },
      { command: 'continue', action: () => handleNext() },
      { command: 'go to next', action: () => handleNext() },
      { command: 'previous', action: () => handlePrevious() },
      { command: 'go back', action: () => handlePrevious() },
      { command: 'skip', action: () => handleSkip() },
      { command: 'skip tour', action: () => handleSkip() },
      { command: 'stop tour', action: () => handleSkip() },
      { command: 'complete', action: () => handleComplete() },
      { command: 'finish tour', action: () => handleComplete() }
    ]);
  }, []);

  // Speak text with natural, human-like voice
  const speakText = (text) => {
    try {
      if (!window.speechSynthesis) return;

      // Wait for voices to load
      const speakWithVoice = () => {
        const voices = window.speechSynthesis.getVoices();
        let selectedVoice = null;

        // Priority list of natural female voices (most natural first)
        const naturalFemaleVoices = [
          'Samantha', // macOS - Very natural
          'Karen', // macOS - Natural
          'Victoria', // macOS - Natural
          'Fiona', // macOS - Natural
          'Moira', // macOS - Natural
          'Tessa', // macOS - Natural
          'Veena', // macOS - Natural
          'Microsoft Zira Desktop', // Windows - Natural
          'Microsoft Hazel Desktop', // Windows - Natural
          'Microsoft Susan Desktop', // Windows - Natural
          'Microsoft Eva Desktop', // Windows - Natural
          'Google UK English Female', // Chrome - Natural
          'Google US English Female', // Chrome - Natural
          'Google Australian English Female', // Chrome - Natural
          'Google Canadian English Female', // Chrome - Natural
          'Google Indian English Female', // Chrome - Natural
          'Google Irish English Female', // Chrome - Natural
          'Google New Zealand English Female', // Chrome - Natural
          'Google South African English Female', // Chrome - Natural
          'Google UK English Female', // Chrome - Natural
          'Google US English Female', // Chrome - Natural
          'Google Welsh English Female' // Chrome - Natural
        ];

        // Look for the most natural female voice
        selectedVoice = voices.find(voice =>
          naturalFemaleVoices.some(name => voice.name.includes(name))
        );

        // If no natural female voice found, look for any female voice
        if (!selectedVoice) {
          selectedVoice = voices.find(voice =>
            voice.name.toLowerCase().includes('female') ||
            voice.name.toLowerCase().includes('woman') ||
            voice.name.toLowerCase().includes('girl')
          );
        }

        // If still no female voice, use the first available voice
        if (!selectedVoice && voices.length > 0) {
          selectedVoice = voices[0];
        }

        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'en-US';

        // Natural speech parameters for human-like voice
        utterance.rate = 0.85; // Slightly slower for natural conversation
        utterance.pitch = 1.15; // Slightly higher for female voice
        utterance.volume = 0.9; // Slightly softer for warmth

        if (selectedVoice) {
          utterance.voice = selectedVoice;
        }

        // Add natural pauses and emphasis
        const naturalText = text
          .replace(/\./g, '. ') // Add pause after periods
          .replace(/,/g, ', ') // Add pause after commas
          .replace(/:/g, ': ') // Add pause after colons
          .replace(/;/g, '; ') // Add pause after semicolons
          .replace(/!/g, '! ') // Add pause after exclamations
          .replace(/\?/g, '? ') // Add pause after questions
          .replace(/\s+/g, ' '); // Clean up extra spaces

        utterance.text = naturalText;

        speakingRef.current = true;
        setIsSpeaking(true);

        utterance.onend = () => {
          speakingRef.current = false;
          setIsSpeaking(false);
        };

        utterance.onerror = () => {
          speakingRef.current = false;
          setIsSpeaking(false);
        };

        window.speechSynthesis.cancel();
        window.speechSynthesis.speak(utterance);
      };

      // If voices are already loaded, speak immediately
      if (window.speechSynthesis.getVoices().length > 0) {
        speakWithVoice();
      } else {
        // Wait for voices to load
        window.speechSynthesis.addEventListener('voiceschanged', speakWithVoice, { once: true });
      }
    } catch (error) {
      console.error('Error speaking text:', error);
    }
  };

  // Initialize speech recognition
  const initRecognition = () => {
    if (recognitionRef.current) return recognitionRef.current;
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) return null;

    const rec = new SpeechRecognition();
    rec.lang = 'en-US';
    rec.interimResults = false;
    rec.maxAlternatives = 1;
    rec.continuous = true;

    rec.onresult = (event) => {
      try {
        const transcript = event.results[event.results.length - 1][0].transcript.toLowerCase().trim();
        console.log('Voice command detected:', transcript);

        // Check for voice commands
        const matchedCommand = voiceCommands.find(cmd =>
          transcript.includes(cmd.command.toLowerCase())
        );

        if (matchedCommand) {
          matchedCommand.action();
          setIsListening(false);
        }
      } catch (error) {
        console.error('Error processing voice command:', error);
      }
    };

    rec.onend = () => setIsListening(false);
    rec.onerror = () => setIsListening(false);

    recognitionRef.current = rec;
    return rec;
  };

  // Toggle voice listening
  const toggleListening = () => {
    const rec = initRecognition();
    if (!rec) {
      alert('Voice recognition not supported in this browser');
      return;
    }

    if (!isListening) {
      try {
        setIsListening(true);
        rec.start();
        speakText("I'm listening for your voice commands. You can say 'next' to continue, 'previous' to go back, 'skip' to skip the tour, or 'complete' to finish. Just speak naturally and I'll understand you.");
      } catch (error) {
        setIsListening(false);
      }
    } else {
      try {
        rec.stop();
      } catch (error) {}
      setIsListening(false);
    }
  };

  // Auto-speak tour instructions when step changes
  useEffect(() => {
    if (currentStep && isTourActive) {
      // Create more natural, conversational instruction text
      const naturalInstruction = `Hi there! ${currentStep.title}. ${currentStep.content}. When you're ready, you can say 'next' to continue, 'previous' to go back, or 'skip' to skip the tour. Take your time!`;
      setTimeout(() => {
        speakText(naturalInstruction);
      }, 800); // Longer delay to allow page navigation to complete
    }
  }, [currentStep, isTourActive]);

  // Cleanup speech recognition on unmount
  useEffect(() => {
    return () => {
      if (recognitionRef.current) {
        try {
          recognitionRef.current.stop();
        } catch (error) {}
      }
    };
  }, []);

  const handleNext = () => {
    nextStep();
  };

  const handlePrevious = () => {
    previousStep();
  };

  const handleComplete = () => {
    completeTour();
  };

  const handleSkip = () => {
    skipTour();
  };

  if (!isTourActive || !currentStep) return null;

  return (
    <div className="fixed top-4 right-4 z-40 bg-white rounded-lg shadow-lg border border-gray-200 max-w-sm">
      {/* Tour Progress Bar */}
      <div className="bg-gradient-to-r from-purple-500 to-pink-500 h-1 rounded-t-lg">
        <div 
          className="bg-white h-full transition-all duration-300 ease-out"
          style={{ width: `${(tourProgress * 100)}%` }}
        />
      </div>

      {/* Tour Content */}
      <div className="p-4">
        {/* Header */}
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center">
              <FaMicrophone className="text-white text-xs" />
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 text-sm">PropertyArk Tour Guide</h3>
              <p className="text-xs text-gray-500">Step {currentTourStep + 1} of {tourSteps.length}</p>
            </div>
          </div>
          <button
            onClick={handleSkip}
            className="text-gray-400 hover:text-gray-600 transition-colors"
            title="Skip Tour"
          >
            <FaTimes size={16} />
          </button>
        </div>

        {/* Step Content */}
        <div className="mb-4">
          <h4 className="font-medium text-gray-900 text-sm mb-2">{currentStep.title}</h4>
          <p className="text-xs text-gray-600 leading-relaxed">{currentStep.content}</p>
        </div>

        {/* Voice Controls */}
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center space-x-2">
            <button
              onClick={toggleListening}
              className={`p-2 rounded-lg transition-colors ${
                isListening ? 'text-red-500 hover:bg-red-50' : 'text-gray-500 hover:bg-gray-50'
              }`}
              title={isListening ? 'Stop listening' : 'Start voice commands'}
            >
              <FaMicrophone size={14} />
            </button>
            {isSpeaking && <FaVolumeUp className="text-blue-500 animate-pulse" size={14} />}
          </div>

          {/* Navigation Buttons */}
          <div className="flex items-center space-x-1">
            <button
              onClick={handlePrevious}
              disabled={currentTourStep === 0}
              className="p-2 rounded-lg transition-colors disabled:text-gray-300 disabled:cursor-not-allowed text-gray-500 hover:bg-gray-50"
              title="Previous Step"
            >
              <FaChevronLeft size={12} />
            </button>
            <button
              onClick={handleNext}
              disabled={currentTourStep === tourSteps.length - 1}
              className="p-2 rounded-lg transition-colors disabled:text-gray-300 disabled:cursor-not-allowed text-gray-500 hover:bg-gray-50"
              title="Next Step"
            >
              <FaChevronRight size={12} />
            </button>
          </div>
        </div>

        {/* Voice Commands Help */}
        <div className="bg-blue-50 p-2 rounded text-xs text-blue-800">
          <strong>🎤 Voice Commands:</strong> Say "next", "previous", "skip", or "complete"
        </div>
      </div>
    </div>
  );
};

