                  <button onClick={() => { setMenuOpen(false); navigate('/profile'); }} className="w-full text-left px-4 py-2 text-sm hover:bg-gray-50">Profile</button>
                  <button onClick={() => { setMenuOpen(false); navigate('/dashboard'); }} className="w-full text-left px-4 py-2 text-sm hover:bg-gray-50">Dashboard</button>
                  {(currentUser?.role === 'admin' || currentUser?.roles?.includes('admin')) && (
                    <button onClick={() => { setMenuOpen(false); navigate('/admin'); }} className="w-full text-left px-4 py-2 text-sm hover:bg-gray-50">Admin Panel</button>
                  )}
                  <div className="border-t" />
                  <button onClick={async () => { setMenuOpen(false); await logout(); navigate('/', { replace: true }); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-gray-50">Logout</button>
                </div>
              )}
            </div>
          ) : (
            <Link to="/auth/login" className="text-sm text-gray-700 hover:text-brand-orange">Sign in</Link>
          )}
        </div>
        {/* Mobile menu button */}
        <button
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="lg:hidden p-2 rounded-lg text-gray-700 hover:text-brand-orange hover:bg-gray-100"
          aria-label="Toggle menu"
        >
          {isMobileMenuOpen ? <FaTimes /> : <FaBars />}
        </button>
      </div>
      {/* Mobile Navigation */}
      {isMobileMenuOpen && (
        <div className="lg:hidden py-2 border-t border-gray-200 shadow-md">
          <nav className="flex flex-col px-4">
            <Link to="/" className="flex items-center min-h-[44px] text-gray-700 hover:text-brand-orange font-medium" onClick={() => setIsMobileMenuOpen(false)}>Home</Link>
            <Link to="/properties?status=For%20Sale" className="flex items-center min-h-[44px] text-gray-700 hover:text-brand-orange font-medium" onClick={() => setIsMobileMenuOpen(false)}>For Sale</Link>
            <Link to="/properties?status=For%20Rent" className="flex items-center min-h-[44px] text-gray-700 hover:text-brand-orange font-medium" onClick={() => setIsMobileMenuOpen(false)}>For Rent</Link>
            <Link to="/properties?status=Shortlet" className="flex items-center min-h-[44px] text-gray-700 hover:text-brand-orange font-medium" onClick={() => setIsMobileMenuOpen(false)}>Shortlet</Link>

            {/* Mobile Professional Services Dropdown */}
            <div>
              <button
                onClick={() => setServicesDropdownOpen(!servicesDropdownOpen)}
                className="w-full min-h-[44px] flex items-center justify-between text-gray-700 hover:text-brand-orange font-medium"
              >
                Professional Services
                <svg className={`w-4 h-4 transition-transform ${servicesDropdownOpen ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
              </button>
              {servicesDropdownOpen && (
                <div className="pl-4 mb-2 space-y-1 border-l-2 border-gray-200">
                  {professionalServices.map((service) => (
                    <button
                      key={service.service}
                      onClick={() => {
                        navigate(`/professional-services/enquiry?service=${encodeURIComponent(service.service)}`);
                        setServicesDropdownOpen(false);
                        setIsMobileMenuOpen(false);
                      }}
                      className="w-full min-h-[44px] flex items-center text-left text-gray-600 hover:text-brand-blue text-sm"
                    >
                      {service.name}
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Mobile auth section */}
            <div className="border-t border-gray-100 pt-1 mt-1">
              {currentUser ? (
                <>
                  <div className="flex items-center gap-3 min-h-[44px] text-sm text-gray-700 font-medium">
                    {currentUser.avatar || currentUser.photoURL ? (
                      <img src={currentUser.avatar || currentUser.photoURL} alt="avatar" className="h-7 w-7 rounded-full object-cover" />
                    ) : (
                      <div className="h-7 w-7 rounded-full bg-brand-blue text-white flex items-center justify-center text-xs font-medium">
                        {(currentUser.firstName || currentUser.displayName || currentUser.email || 'U')[0].toUpperCase()}
                      </div>
                    )}
                    <span>{currentUser.firstName || currentUser.displayName || (currentUser.email && currentUser.email.split('@')[0])}</span>
                  </div>
                  <button onClick={() => { setIsMobileMenuOpen(false); navigate('/dashboard'); }} className="w-full min-h-[44px] flex items-center text-gray-700 hover:text-brand-orange font-medium text-sm">Dashboard</button>
                  <button onClick={() => { setIsMobileMenuOpen(false); navigate('/profile'); }} className="w-full min-h-[44px] flex items-center text-gray-700 hover:text-brand-orange font-medium text-sm">Profile</button>
                  {(currentUser?.role === 'admin' || currentUser?.roles?.includes('admin')) && (
                    <button onClick={() => { setIsMobileMenuOpen(false); navigate('/admin'); }} className="w-full min-h-[44px] flex items-center text-gray-700 hover:text-brand-orange font-medium text-sm">Admin Panel</button>
                  )}
                  <button
                    onClick={async () => { setIsMobileMenuOpen(false); await logout(); navigate('/', { replace: true }); }}
                    className="w-full min-h-[44px] flex items-center text-red-600 hover:text-red-700 font-medium text-sm"
                  >
                    Logout
                  </button>
                </>
              ) : (
                <Link to="/auth/login" className="flex items-center min-h-[44px] text-brand-blue hover:text-brand-orange font-medium" onClick={() => setIsMobileMenuOpen(false)}>Sign in</Link>
              )}
            </div>
          </nav>
        </div>
      )}
    </header>
  );
}

﻿import React, { useState } from 'react';
import { NavLink, Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useVendor } from '../../contexts/VendorContext';
import { useSidebar } from '../../contexts/SidebarContext';
import { 
  FaHome, 
  FaPlus, 
  FaBuilding, 
  FaUsers, 
  FaDollarSign, 
  FaCog, 
  FaFileContract,
  FaBell,
  FaQuestionCircle,
  FaSignOutAlt,
  FaChevronLeft,
  FaChevronRight,
  FaUser,
  FaTimes
} from 'react-icons/fa';

const VendorSidebar = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { logout, user } = useAuth();
  const { isAgent, isPropertyOwner, documentStatus } = useVendor();
  const { isCollapsed, toggleSidebar, isMobileSidebarOpen, closeMobileSidebar } = useSidebar();
  
  const menuItems = [
    { path: '/vendor/dashboard', label: 'Overview', icon: FaHome },
    { path: '/vendor/properties', label: 'My Properties', icon: FaBuilding },
    { path: '/vendor/inspection-requests', label: 'Inspection Requests', icon: FaBell },
    { path: '/vendor/earnings', label: 'Earnings', icon: FaDollarSign },
    { path: '/vendor/contracts', label: 'Contracts', icon: FaFileContract },
    { path: '/vendor/subscription', label: 'Subscription', icon: FaDollarSign }
  ];

  const accountItems = [
    { path: '/vendor/profile', label: 'Profile Settings', icon: FaCog }
  ];

  const isActive = (path) => {
    return location.pathname === path;
  };

  const handleSignOut = async () => {
    try {
      await logout();
      navigate('/');
    } catch (error) {
      console.error('Error signing out:', error);
    }
  };

  const safeString = (value, fallback = '') => (typeof value === 'string' ? value : fallback);

  const getUserInitials = () => {
    const displayName = safeString(user?.displayName);
    if (displayName) {
      return displayName
        .split(' ')
        .filter(Boolean)
        .map((n) => n[0])
        .join('')
        .toUpperCase();
    }

    const email = safeString(user?.email);
    if (email) {
      return email[0].toUpperCase();
    }

    return 'U';
  };

  const getUserDisplayName = () => {
    const displayName = safeString(user?.displayName);
    if (displayName) return displayName;

    const email = safeString(user?.email);
    if (email) {
      const [prefix] = email.split('@');
      return prefix || 'Vendor Account';
    }

    return 'Vendor Account';
  };

  const getActiveSection = () => {
    const path = location.pathname;
    if (path.startsWith('/vendor/dashboard')) return 'main';
    if (path.startsWith('/vendor/profile')) return 'account';
    if (path.startsWith('/vendor/notifications') || path.startsWith('/vendor/help')) return 'support';
    return 'main';
  };

  return (
    <>
      {isMobileSidebarOpen && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 z-[60] lg:hidden"
          onClick={closeMobileSidebar}
        />
      )}
      <div className={`${isCollapsed ? 'w-16' : 'w-64'} bg-white shadow-lg h-full fixed left-0 top-0 overflow-y-auto flex flex-col transition-all duration-300 z-[70] transform lg:translate-x-0 ${isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}`}>
      {/* Logo */}
      <div className="px-4 py-4 border-b border-gray-200 flex-shrink-0">
        <div className="flex items-center justify-between mb-2">
          <Link to="/" className="flex items-center flex-shrink-0 focus:outline-none focus:ring-0 border-none hover:opacity-80 transition-opacity">
            <img 
              src={`${process.env.PUBLIC_URL}/logo.png?v=4.0`} 
              alt="PropertyArk Logo" 
              className="w-auto h-20 sm:h-24 md:h-28"
              style={{ 
                maxHeight: '7rem',
                backgroundColor: 'transparent',
                mixBlendMode: 'normal',
                border: 'none',
                outline: 'none'
              }}
              onError={(e) => {
                // Fallback to icon if logo image doesn't exist
                e.target.style.display = 'none';
                e.target.nextSibling.style.display = 'flex';
              }}
            />
            <div className="w-8 h-8 bg-gradient-to-r from-brand-blue to-blue-600 rounded-lg flex items-center justify-center" style={{ display: 'none' }}>
              <FaHome className="text-white text-sm" />
            </div>
          </Link>
          <div className="flex items-center gap-1">
            <button
              onClick={closeMobileSidebar}
              className="p-1 hover:bg-gray-100 rounded-lg transition-colors lg:hidden"
              aria-label="Close sidebar"
            >
              <FaTimes className="h-4 w-4 text-gray-600" />
            </button>
            <button
              onClick={toggleSidebar}
              className="p-1 hover:bg-gray-100 rounded-lg transition-colors hidden lg:block"
              aria-label={isCollapsed ? 'Expand sidebar' : 'Collapse sidebar'}
            >
              {isCollapsed ? <FaChevronRight className="h-4 w-4 text-gray-600" /> : <FaChevronLeft className="h-4 w-4 text-gray-600" />}
            </button>
          </div>
        </div>
        {!isCollapsed && (
          <p className="text-xs text-gray-500 ml-1">Vendor Portal</p>
        )}
      </div>

      {/* Navigation Menu */}
      <nav className="px-4 pt-2 pb-4 flex-1">
        {/* Main Menu Section */}
        <div className="mb-8">
          {!isCollapsed && (
            <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Main Menu</h3>
          )}
          <ul className="space-y-1">
            {menuItems.map((item) => (
              <li key={item.path}>
                <NavLink
                  to={item.path}
                  end
                  className={({ isActive }) => `flex items-center space-x-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors group relative ${
                    isActive ? 'bg-brand-blue text-white' : 'text-gray-700 hover:bg-gray-100'
                  }`}
                  title={isCollapsed ? item.label : undefined}
                >
                  <item.icon className="h-4 w-4 flex-shrink-0" />
                  {!isCollapsed && <span>{item.label}</span>}
                  {isCollapsed && (
                    <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity duration-200 pointer-events-none whitespace-nowrap z-50">
                      {item.label}
                    </div>
                  )}
                </NavLink>
              </li>
            ))}
          </ul>
        </div>

        {/* Account Section */}
        <div className="mb-8">
          {!isCollapsed && (
            <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Account</h3>
          )}
          <ul className="space-y-1">
            {accountItems.map((item) => (
              <li key={item.path}>
                <NavLink
                  to={item.path}
                  end
                  className={({ isActive }) => `flex items-center space-x-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors group relative ${
                    isActive ? 'bg-brand-blue text-white' : 'text-gray-700 hover:bg-gray-100'
                  }`}
                  title={isCollapsed ? item.label : undefined}
                >
                  <item.icon className="h-4 w-4 flex-shrink-0" />
                  {!isCollapsed && <span>{item.label}</span>}
                  {isCollapsed && (
                    <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity duration-200 pointer-events-none whitespace-nowrap z-50">
                      {item.label}
                    </div>
                  )}
                </NavLink>
              </li>
            ))}
          </ul>
        </div>

        {/* Support Section */}
        <div className="mb-8">
          {!isCollapsed && (
            <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Support</h3>
          )}
          <ul className="space-y-1">
            <li>
              <NavLink
                to="/vendor/help"
                end
                className={({ isActive }) => `flex items-center space-x-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors group relative ${
                  isActive ? 'bg-brand-blue text-white' : 'text-gray-700 hover:bg-gray-100'
                }`}
                title={isCollapsed ? 'Help & Support' : undefined}
              >
                <FaQuestionCircle className="h-4 w-4 flex-shrink-0" />
                {!isCollapsed && <span>Help & Support</span>}
                {isCollapsed && (
                  <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity duration-200 pointer-events-none whitespace-nowrap z-50">
                    Help & Support
                  </div>
                )}
              </NavLink>
            </li>
          </ul>
        </div>
      </nav>

      {/* Bottom Section */}
      <div className="mt-auto border-t border-gray-200 bg-white">
        {/* User Profile Section */}
        <div className="p-4">
        <div className="mb-4 p-3 bg-gray-50 rounded-lg">
          <div className="flex items-center space-x-3 mb-3">
            <div className="w-8 h-8 bg-gradient-to-r from-brand-blue to-blue-600 rounded-full flex items-center justify-center">
              {user?.photoURL ? (
                <img 
                  src={user?.photoURL} 
                  alt="User avatar" 
                  className="w-8 h-8 rounded-full object-cover"
                />
              ) : (
                <span className="text-sm font-medium text-white">{getUserInitials()}</span>
              )}
            </div>
            {!isCollapsed && (
              <div className="flex-1">
                <p className="text-sm font-medium text-gray-900">
                  {getUserDisplayName()}
                </p>
                <div className="flex flex-wrap gap-1 mt-1">
                  {isAgent && (
                    <span className="text-xs bg-orange-100 text-orange-800 px-2 py-1 rounded-full">
                      Agent
                    </span>
                  )}
                  {isPropertyOwner && (
                    <span className="text-xs bg-blue-100 text-blue-800 px-2 py-1 rounded-full">
                      Owner
                    </span>
                  )}
                  {isAgent && documentStatus && (
                    <span className={`text-xs px-2 py-1 rounded-full ${
                      documentStatus.attestationStatus === 'verified' 
                        ? 'bg-green-100 text-green-800' 
                        : 'bg-yellow-100 text-yellow-800'
                    }`}>
                      {documentStatus.attestationStatus === 'verified' ? 'Verified' : 'Pending'}
                    </span>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
        
        {/* Sign Out Button */}
        <button 
          onClick={handleSignOut}
          className="w-full flex items-center space-x-3 px-3 py-2 text-sm font-medium text-gray-700 hover:bg-gray-100 rounded-lg transition-colors group relative"
          title={isCollapsed ? 'Sign Out' : undefined}
        >
          <FaSignOutAlt className="h-4 w-4 flex-shrink-0" />
          {!isCollapsed && <span>Sign Out</span>}
          {isCollapsed && (
            <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity duration-200 pointer-events-none whitespace-nowrap z-50">
              Sign Out
            </div>
          )}
        </button>
        </div>
      </div>
    </div>
    </>
  );
};

export default VendorSidebar;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import toast from 'react-hot-toast';
import { getApiUrl } from '../../utils/apiConfig';
import apiClient from '../../services/apiClient';

const CreateTicketModal = ({ onClose, onSuccess }) => {
  const { currentUser } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    subject: '',
    category: '',
    priority: 'medium',
    message: '',
    contactEmail: currentUser?.email || '',
    contactPhone: currentUser?.phone || currentUser?.phoneNumber || ''
  });
  const [submitting, setSubmitting] = useState(false);

  const resolveUserId = () => {
    if (!currentUser) return null;
    return currentUser.id || currentUser.uid || currentUser._id || currentUser.userId || null;
  };

  const handleSubmit = async (e) => {
    e && e.preventDefault();
    if (!form.subject || !form.category || !form.message) {
      toast.error('Please complete subject, category and message');
      return;
    }

    const userId = resolveUserId();
    if (!userId) {
      toast.error('Please log in to submit a support ticket');
      // Do not redirect to login modal after submission attempt
      return;
    }

    setSubmitting(true);
    try {
      const payload = {
        subject: form.subject,
        message: form.message,
        category: form.category,
        priority: form.priority,
        contactEmail: form.contactEmail?.trim() || undefined,
        contactPhone: form.contactPhone?.trim() || undefined,
        userId
      };

      const resp = await apiClient.post('/support/inquiry', payload);

      if (resp?.data?.success) {
        toast.success(resp.data?.message || 'Support ticket submitted. We will respond by email.');
        setForm({
          subject: '',
          category: '',
          priority: 'medium',
          message: '',
          contactEmail: currentUser?.email || '',
          contactPhone: currentUser?.phone || currentUser?.phoneNumber || ''
        });
        if (onSuccess) onSuccess();
        if (onClose) onClose();
      } else if (resp?.status === 401 || resp?.data?.status === 401) {
        toast.error('Authentication required. Please log in again.');
      } else {
        const err = resp?.data || {};
        toast.error(err.error || `Failed to submit ticket`);
      }
    } catch (error) {
      console.error('Create ticket error:', error);
      toast.error('Failed to submit support ticket. Please try again later.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div className="absolute inset-0 bg-black/50" onClick={() => onClose && onClose()} />
      <div className="relative w-full max-w-2xl rounded-lg bg-white p-6 shadow-lg">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-semibold">Create Support Ticket</h3>
          <button onClick={() => onClose && onClose()} className="text-gray-600">✕</button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label htmlFor="ticket-subject" className="block text-sm font-medium text-gray-700 mb-1">Subject</label>
              <input
                id="ticket-subject"
                value={form.subject}
                onChange={(e) => setForm(f => ({ ...f, subject: e.target.value }))}
                className="w-full px-3 py-2 border rounded"
                required
              />
            </div>
            <div>
              <label htmlFor="ticket-category" className="block text-sm font-medium text-gray-700 mb-1">Category</label>
              <select
                id="ticket-category"
                value={form.category}
                onChange={(e) => setForm(f => ({ ...f, category: e.target.value }))}
                className="w-full px-3 py-2 border rounded"
                required
              >
                <option value="">Select a category</option>
                <option value="general">General Inquiry</option>
                <option value="technical">Technical Support</option>
                <option value="billing">Billing & Payments</option>
                <option value="investment">Investment</option>
                <option value="mortgage">Mortgage</option>
                <option value="property">Property Related</option>
                <option value="other">Other</option>
              </select>
            </div>
          </div>

          <div>
            <label htmlFor="ticket-priority" className="block text-sm font-medium text-gray-700 mb-1">Priority</label>
            <select
              id="ticket-priority"
              value={form.priority}
              onChange={(e) => setForm(f => ({ ...f, priority: e.target.value }))}
              className="w-full px-3 py-2 border rounded"
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
              <option value="critical">Critical</option>
            </select>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label htmlFor="ticket-email" className="block text-sm font-medium text-gray-700 mb-1">Reply-to Email</label>
              <input
                id="ticket-email"
                type="email"
                value={form.contactEmail}
                onChange={(e) => setForm(f => ({ ...f, contactEmail: e.target.value }))}
                className="w-full px-3 py-2 border rounded"
                placeholder="you@example.com"
              />
              <p className="mt-1 text-xs text-gray-500">We'll reach you at this address.</p>
            </div>
            <div>
              <label htmlFor="ticket-phone" className="block text-sm font-medium text-gray-700 mb-1">Phone (optional)</label>
              <input
                id="ticket-phone"
                type="tel"
                value={form.contactPhone}
                onChange={(e) => setForm(f => ({ ...f, contactPhone: e.target.value }))}
                className="w-full px-3 py-2 border rounded"
                placeholder="+234 812 000 0000"
              />
            </div>
          </div>

          <div>
            <label htmlFor="ticket-message" className="block text-sm font-medium text-gray-700 mb-1">Message</label>
            <textarea
              id="ticket-message"
              value={form.message}
              onChange={(e) => setForm(f => ({ ...f, message: e.target.value }))}
              rows={6}
              className="w-full px-3 py-2 border rounded"
              required
            />
          </div>

          <div className="flex items-center space-x-3">
            <button type="submit" disabled={submitting} className="btn-primary">
              {submitting ? 'Submitting…' : 'Submit Ticket'}
            </button>
            <button type="button" onClick={() => onClose && onClose()} className="btn-outline">Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
};

