                      const roleClass = u.role === 'admin' ? 'text-purple-600 bg-purple-50' : u.role === 'vendor' ? 'text-blue-600 bg-blue-50' : 'text-amber-600 bg-amber-50';
                      return (
                        <tr key={u.id} className={isSelected ? 'bg-blue-50/40' : undefined}>
