            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-lg font-semibold text-gray-900">
                    {escrowActionType === 'status' ? 'Update Escrow Status' : 'Resolve Escrow Dispute'}
