                  <HiOutlineX className="w-5 h-5" />
                </button>
              </div>

              {escrowActionType === 'status' ? (
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Escrow Status</label>
                  <select
                    value={escrowStatusValue}
