                  className="px-4 py-2 rounded-lg bg-brand-blue text-white hover:bg-brand-blue/90 disabled:opacity-60"
                >
                  {escrowActionLoading ? 'Processing...' : 'Confirm Action'}
                </button>
              </div>
            </div>
          </div>
        </div>
