                </div>
                <input
                  type="text"
                  value={blogEditor.title}
                  onChange={(e) => handleBlogEditorChange('title', e.target.value)}
                  placeholder="Post title (10-200 characters minimum)"
                  className={`w-full px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-brand-blue ${
                    blogEditor.title.length > 0 && (blogEditor.title.length < 10 || blogEditor.title.length > 200) ? 'border-red-300' : 'border-gray-300'
                  }`}
