                {blogEditor.title.length > 200 && (
                  <p className="text-red-500 text-xs mt-1">Title must not exceed 200 characters</p>
                )}
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Category</label>
                <select
                  value={blogEditor.category}
                  onChange={(e) => handleBlogEditorChange('category', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-brand-blue"
                >
                  {BLOG_CATEGORY_OPTIONS.map((cat) => (
                    <option key={cat} value={cat}>
                      {cat.split('-').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ')}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Status</label>
                <select
                  value={blogEditor.status}
                  onChange={(e) => handleBlogEditorChange('status', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-brand-blue"
                >
                  {BLOG_STATUS_OPTIONS.map((status) => (
                    <option key={status} value={status}>
                      {status.charAt(0).toUpperCase() + status.slice(1)}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <div className="flex justify-between items-center mb-2">
                  <label className="block text-sm font-medium text-gray-700">
                    Excerpt <span className="text-gray-400">(optional)</span>
                  </label>
                  <span className={`text-xs ${blogEditor.excerpt.length > 0 && (blogEditor.excerpt.length < 50 || blogEditor.excerpt.length > 500) ? 'text-red-500' : blogEditor.excerpt.length > 0 ? 'text-green-600' : 'text-gray-400'}`}>
                    {blogEditor.excerpt.length > 0 ? `${blogEditor.excerpt.length}/500 characters` : 'Optional'}
                  </span>
                </div>
                <textarea
                  rows={2}
                  value={blogEditor.excerpt}
                  onChange={(e) => handleBlogEditorChange('excerpt', e.target.value)}
