                    blogEditor.excerpt.length > 0 && (blogEditor.excerpt.length < 50 || blogEditor.excerpt.length > 500) ? 'border-red-300' : 'border-gray-300'
                  }`}
                />
                {blogEditor.excerpt.length > 0 && blogEditor.excerpt.length < 50 && (
                  <p className="text-red-500 text-xs mt-1">Excerpt must be at least 50 characters if provided</p>
                )}
                {blogEditor.excerpt.length > 500 && (
                  <p className="text-red-500 text-xs mt-1">Excerpt must not exceed 500 characters</p>
                )}
              </div>
              <div>
                <div className="flex justify-between items-center mb-2">
                  <label className="block text-sm font-medium text-gray-700">
                    Content <span className="text-red-500">*</span>
                  </label>
                  <span className={`text-xs ${blogEditor.content.length < 100 ? 'text-red-500' : 'text-green-600'}`}>
                    {blogEditor.content.length}/100 characters minimum
                  </span>
                </div>
                <textarea
                  rows={6}
                  value={blogEditor.content}
                  onChange={(e) => handleBlogEditorChange('content', e.target.value)}
                  placeholder="Share insights, data, or announcements... (minimum 100 characters required)"
                  className={`w-full px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-brand-blue ${
                    blogEditor.content.length < 100 ? 'border-red-300' : 'border-gray-300'
                  }`}
                />
