                className="px-4 py-2 bg-brand-blue text-white rounded-md hover:bg-brand-blue/90 disabled:opacity-50 disabled:cursor-not-allowed"
                title={
                  blogEditor.title.length < 10 ? 'Title must be at least 10 characters' :
                  blogEditor.title.length > 200 ? 'Title must not exceed 200 characters' :
                  blogEditor.content.length < 100 ? 'Content must be at least 100 characters' :
                  blogEditor.excerpt.length > 0 && blogEditor.excerpt.length < 50 ? 'Excerpt must be at least 50 characters' :
                  blogEditor.excerpt.length > 500 ? 'Excerpt must not exceed 500 characters' :
                  ''
                }
              >
                {blogSaving ? 'Saving...' : 'Save Post'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Property Details Modal */}
      <AdminPropertyDetailsModal
        property={selectedPropertyForModal}
        isOpen={showPropertyModal}
        onClose={closePropertyModal}
        onApprove={handlePropertyApprove}
        onReject={handlePropertyReject}
      />
      </div>
    </div>
  );
};

