            <div className="p-3 bg-blue-100 rounded-lg">
              <FaLock className="text-blue-600 text-xl" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-600">Funds in Escrow</p>
              <p className="text-2xl font-bold text-gray-900">
