            <span className="flex items-center bg-orange-500 text-white px-3 py-1 rounded-full text-sm">
              {appliedLocation}
              <FaTimes
                className="ml-2 cursor-pointer"
                onClick={() => {
                  setAppliedLocation('');
                  setSelectedLocation('');
                }}
              />
            </span>
          )}
          {appliedStatus && (
            <span className="flex items-center bg-orange-500 text-white px-3 py-1 rounded-full text-sm">
              {appliedStatus}
              <FaTimes
                className="ml-2 cursor-pointer"
                onClick={() => {
                  setAppliedStatus('');
                  setSelectedStatus('');
                }}
              />
            </span>
          )}
          {appliedType && (
            <span className="flex items-center bg-orange-500 text-white px-3 py-1 rounded-full text-sm">
              {appliedType}
              <FaTimes
                className="ml-2 cursor-pointer"
