                }}
              />
            </span>
          )}
          {appliedVendor && (
            <span className="flex items-center bg-orange-500 text-white px-3 py-1 rounded-full text-sm">
              Vendor (hidden)
              <FaTimes
                className="ml-2 cursor-pointer"
                onClick={() => {
                  setAppliedVendor('');
                  setSelectedVendor('');
                }}
              />
