              if (totalPages <= 7) {
                // Show all pages if 7 or fewer
                startPage = 1;
                endPage = totalPages;
              } else {
                // Show pages around current page
                if (currentPage <= 4) {
                  startPage = 1;
                  endPage = 5;
                } else if (currentPage >= totalPages - 3) {
                  startPage = totalPages - 4;
                  endPage = totalPages;
                } else {
                  startPage = currentPage - 2;
                  endPage = currentPage + 2;
