                    </div>
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        handleScheduleViewing(property);
                      }}
                      className="w-full bg-green-600 text-white py-2 px-4 rounded-lg hover:bg-green-700 transition-colors flex items-center justify-center"
