          const property = properties.find(p => {
            const propId = p.id || p.propertyId || p._id;
            const propIdStr = String(propId || '');

            // Compare as strings for consistent matching
            const matches = (
              propIdStr === favoriteIdStr ||
              propId === favoriteId ||
              String(propId) === String(favoriteId)
            );

            return matches;
