    }

    // Extract amenities
    const amenities = ['pool', 'gym', 'security', 'parking', 'garden', 'balcony', 'elevator', 'wifi', 'ac', 'furnished', 'unfurnished'];
    for (const amenity of amenities) {
      if (message.toLowerCase().includes(amenity)) {
        entities.amenities.push(amenity);
      }
